/**** throwError - simplifies construction of named errors ****/

  export function throwError (Message:string):never {
debugger               // not to be removed (helps debugging within the browser)
    const Match = /^([$a-zA-Z][$a-zA-Z0-9]*):\s*(\S.+)\s*$/.exec(Message)
    if (Match == null) {
      throw new Error(Message)
    } else {
      const namedError = new Error(Match[2])
        namedError.name = Match[1]!
      throw namedError
    }
  }

/**** throwReadOnlyError ****/

  export function throwReadOnlyError (Name:string):never {
    return throwError(
      'ReadOnlyProperty: property ' + quoted(Name) + ' must not be set'
    )
  }

