/**** ValueIsTextWithTabs ****/

// like "ValueIsText" (from "javascript-interface-library") - but additionally
// permits horizontal tabs (\x09), which "ValueIsText" treats as forbidden
// control characters. useful for multi-line inputs (such as
// "nativeTextInput") and, e.g., tabular sticky note contents

  const JCL_TextWithTabsPattern = new RegExp(
    '^[^\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F-\\x9F' +
    '\\u2028\\u2029\\uFFF9-\\uFFFB]*$'
  )

  export function ValueIsTextWithTabs (Value:any):boolean {
    return ValueIsString(Value) && JCL_TextWithTabsPattern.test(Value)
  }/**** ValueIsPromise ****/

  export function ValueIsPromise (Value:any):boolean {
    return (
      (ValueIsObject(Value) || ValueIsFunction(Value)) &&
      ValueIsFunction(Value.then)
    )
  }

/**** allow/expect[ed]Promise ****/

  export const [ allowPromise,allowedPromise, expectPromise,expectedPromise ] =
    /*@__PURE__*/ ValidatorQuadrupleFor(ValueIsPromise,'JavaScript Promise or thenable')

/**** ValueIsAbortSignal ****/

  export function ValueIsAbortSignal (Value:any):boolean {
    return (
      (typeof Value === 'object') && (Value != null) &&
      (typeof Value.aborted === 'boolean') &&
      (typeof Value.addEventListener === 'function')
    )
  }

/**** allow/expect[ed]AbortSignal ****/

  export const [ allowAbortSignal,allowedAbortSignal, expectAbortSignal,expectedAbortSignal ] =
    /*@__PURE__*/ ValidatorQuadrupleFor(ValueIsAbortSignal,'JavaScript abort signal')

