/**** InternetIsAvailable ****/

  export async function InternetIsAvailable (
    ServerURL:JCL_URL = 'https://cloudflare.com/cdn-cgi/trace',
    Timeout:number = 5000
  ):Promise<boolean> {
//  expectURL  ('server URL',ServerURL)   // will be done by "ServerIsReachable"
//  expectCardinal('timeout',Timeout)

    if ((typeof navigator !== 'undefined') && (! navigator.onLine)) {
      return false                         // fast, but not necessarily reliable
    }

    return await ServerIsReachable(ServerURL,Timeout)
  }

/**** ServerIsReachable ****/

  export async function ServerIsReachable (
    ServerURL:JCL_URL, Timeout:number = 5000
  ):Promise<boolean> {
    expectURL  ('server URL',ServerURL)
    expectCardinal('timeout',Timeout)

    const ServerOrigin = new URL(ServerURL).origin   // keeps scheme, host, port
    if (ServerOrigin === window.location.origin) { return true }

    const TimeoutController = new AbortController()

    const RequestTimer = setTimeout(
      () => TimeoutController.abort(), Timeout
    )

    try {
      const Response = await fetch(ServerOrigin, {
        method:'HEAD',
        signal:TimeoutController.signal,
        mode:  'no-cors',
        cache: 'no-cache'
      })

      clearTimeout(RequestTimer)
      return (Response.type === 'basic') || (Response.type === 'opaque')
    } catch (Signal) {
      clearTimeout(RequestTimer)
      return false
    }
  }
/**** fetched ****/

  export async function fetched (
    ResourceURL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<any> {
    expectURL      ('resource URL',ResourceURL)
    expectPlainObject('option set',OptionSet)

    OptionSet = {...OptionSet}                   // allows modifying "OptionSet"

  /**** basic Connectivity Handling ****/

    if ((typeof navigator !== 'undefined') && (! navigator.onLine)) throwError(
      'NotConnected: the browser is not connected'
    )

  /**** Preparation: Timeout and Retry Handling ****/

    const Timeout = allowedCardinal('request timeout',OptionSet.timeout) ?? 10*1000

    const allowRetries = (OptionSet.allowRetries === true)
    const maxRetries   = allowedCardinal('maximum retries',OptionSet.maxRetries) ?? 3

    delete OptionSet.timeout                      // not standard "fetch" options
    delete OptionSet.allowRetries
    delete OptionSet.maxRetries

    const CallerSignal = OptionSet.signal as AbortSignal | undefined

  /**** computes the delay before the next retry (honours "Retry-After") ****/

    function _retryDelay (ResponseObject:Response, Attempt:number):number {
      const Header = ResponseObject.headers.get('Retry-After')
      if (Header != null) {
        const Seconds = parseInt(Header,10)
        if (! isNaN(Seconds)) { return Math.max(0, Seconds * 1000) }

        const DateMillis = Date.parse(Header)
        if (! isNaN(DateMillis)) { return Math.max(0, DateMillis - Date.now()) }
      }
      return Math.min(30*1000, 500 * 2**Attempt)          // exponential backoff
    }

  /**** now fetch (with optional retries) and handle runtime errors ****/

    let Attempt = 0
    while (true) {
      const TimeoutController = new AbortController()
      OptionSet.signal = (CallerSignal != null)
        ? AbortSignal.any([TimeoutController.signal, CallerSignal])
        : TimeoutController.signal

      let RequestTimedOut = false
      const RequestTimer = setTimeout(() => {
        RequestTimedOut = true
        TimeoutController.abort()
      }, Timeout)

      let Response
      try {
        Response = await fetch(ResourceURL,OptionSet)
        clearTimeout(RequestTimer)
      } catch (Signal:any) {
        clearTimeout(RequestTimer)
        const Message:string = Signal?.message ?? ''
        if (                 // timeout by fetch or cancellation by internal timer
          RequestTimedOut || Message.includes('timeout')
        ) throwError('ServerUnreachable: the server is unreachable')

        if (                                              // explicit cancellation
          (Signal?.name === 'AbortError') ||
          Message.includes('The user aborted a request')
        ) throwError(
          'RequestAborted: request was aborted'
        )

        if (
          Message.includes('Failed to fetch') ||
          Message.includes('CORS')
        ) throwError('CORSblocked: cross-origin request blocked')

        if (
          (Signal?.name === 'TypeError') &&
          (typeof navigator !== 'undefined') && (! navigator.onLine)
        ) throwError(
          'NotConnected: the browser is offline'
        )

        throwError('ServerUnreachable: the server is unreachable')
      }

    /**** retry on 429/503 when explicitly allowed ****/

      if (
        allowRetries && (Attempt < maxRetries) &&
        ((Response.status === 429) || (Response.status === 503))
      ) {
        await new Promise(
          (resolve) => setTimeout(resolve, _retryDelay(Response,Attempt))
        )
        Attempt++
        continue
      }

    /**** HTTP Status Code Handling ****/

      switch (true) {
        case (Response.status === 401):
          throwError('AuthorizationFailure: authorization failed')
        case (Response.status === 403):
          throwError('ForbiddenRequest: request is forbidden')
        case (Response.status === 404):
          throwError('MissingResource: resource not found')
        case (Response.status === 408):
          throwError('RequestTimeout: request timed out')
        case (Response.status === 429):
          throwError('RateLimitExceeded: too many requests')
        case (Response.status === 500):
          throwError('InternalServerError: internal server error')
        case (Response.status === 502):
          throwError('BadGateway: bad gateway')
        case (Response.status === 503):
          throwError('ServiceUnavailable: service is currently not available')
        case (Response.status === 504):
          throwError('GatewayTimeout: gateway timed out')
        case (Response.status >= 400):
          throwError(
            'HTTPError: request failed with status ' + Response.status
          )
      }

    /**** otherwise: success! ****/

      return Response
    }
  }
/**** fetchedText ****/

  export async function fetchedText (
    URL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<JCL_Text> {
    const Result = await fetched(URL,OptionSet)
    return await Result.text()
  }

