/**** fetchedDataURL ****/

  export async function fetchedDataURL (
    URL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<JCL_URL> {
    const Result = await fetched(URL,OptionSet)
    const Blob   = await Result.blob()

    let resolve!:(Value:JCL_URL) => void, reject!:(Reason?:any) => void
    const promise = new Promise<JCL_URL>((_resolve,_reject) => {
      resolve = _resolve; reject = _reject
    })
      const Reader = new FileReader()
        Reader.onloadend = () => resolve(Reader.result as JCL_URL)
        Reader.onerror   = reject
      Reader.readAsDataURL(Blob)
    return promise
  }

/**** fetchedAsText ****/

  export async function fetchedAsText (
    URL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<string> {
    const Response = await fetched(URL,OptionSet)

    const Type = (Response.headers.get('content-type') ?? '').split(';')[0]!.trim()
    switch (true) {
      case Type.startsWith('text/html'): return await HTMLasText(await Response.text())
      case (Type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'):
                                         return await DOCXasText(await Response.arrayBuffer())
      case (Type === 'application/pdf'): return await PDFasText (await Response.arrayBuffer())
      case Type.startsWith('text/markdown'):
                                         return await MarkdownAsText(await Response.text())
      case Type.startsWith('text/'):
      case Type.includes('javascript'):
      case Type.includes('typescript'):
      case Type.includes('json'):
      case Type.includes('css'):
      case Type.includes('svg'):
      case Type.includes('xml'):        return await Response.text()
      default: throwError(`UnsupportedMIMEType: cannot convert content of type "${Type}" into plain text`)
    }
  }

/**** fetchedAsHTML ****/

  export async function fetchedAsHTML (
    URL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<string> {
    const Response = await fetched(URL,OptionSet)

    const Type = (Response.headers.get('content-type') ?? '').split(';')[0]!.trim()
    switch (true) {
      case Type.startsWith('text/html'):     return await Response.text()
      case (Type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'):
                                             return await DOCXasHTML(await Response.arrayBuffer())
      case Type.startsWith('text/markdown'): return await MarkdownAsHTML(await Response.text())
      default: throwError(`UnsupportedMIMEType: cannot convert content of type "${Type}" into HTML`)
    }
  }

/**** fetchedAsMarkdown ****/

  export async function fetchedAsMarkdown (
    URL:JCL_URL, OptionSet:Indexable = {}
  ):Promise<string> {
    const Response = await fetched(URL,OptionSet)

    const Type = (Response.headers.get('content-type') ?? '').split(';')[0]!.trim()
    switch (true) {
      case Type.startsWith('text/html'):     return await HTMLasMarkdown(await Response.text())
      case (Type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'):
                                             return await DOCXasMarkdown(await Response.arrayBuffer())
      case Type.startsWith('text/markdown'): return await Response.text()
      default: throwError(`UnsupportedMIMEType: cannot convert content of type "${Type}" into Markdown`)
    }
  }

