  export function DescriptionOfHTTPStatus (StatusCode:JCL_Ordinal):JCL_Textline {
    expectIntegerInRange('HTTP status code',StatusCode, 100,599)
    return HTTPMessageForStatus[StatusCode] ?? ''
  }

