//------------------------------------------------------------------------------
//--                              Normalizations                              --
//------------------------------------------------------------------------------

/**** normalizedName ****/

  export function normalizedName (Name:JCL_Name):JCL_Name {
    expectName('name',Name)
    return _normalizedName(Name)                                          // DRY
  }

/**** _normalizedName — replaces dots with hyphens for use in CSS ids ****/

  function _normalizedName (Name:string):string {
    return Name.replaceAll('.', '-')
  }

/**** parsedOption ****/

// splits a "Value:Label" option textline (as used by drop-downs, radio groups,
// multi-switches etc.) into its parts - a leading "-" marks the option as
// disabled, a label consisting of dashes only serves as a separator ("ruler")

  export function parsedOption (Option:string):Indexable {
    let   Value    = Option.replace(/:.*$/,'').trim()
    let   Label    = Option.replace(/^[^:]*:/,'').trim()
    const isRuler  = /^[-]+$/.test(Label)
    const disabled = (Label[0] === '-')

    if (Value === Option) { Value = Value.replace(/^-/,'') }
    if (disabled)         { Label = Label.replace(/^-/,'') }

    return { Value,Label, disabled,isRuler }
  }

//------------------------------------------------------------------------------
//--                             PropSet Parsing                              --
//------------------------------------------------------------------------------

  export function parseablePropSet (PropSet:Indexable):Indexable {
    expectPlainObject('PropSet',PropSet)

  /**** normalise all keys to lower-case in a fresh backing object ****/

    const Backing:Indexable = {}
    for (const Key of Object.keys(PropSet)) {
      Backing[_normalizedKey(Key)] = PropSet[Key]
    }

  /**** "children" and "RestProps" are somewhat special ****/

    Backing.children = toChildArray(PropSet.children)  // single children are no arrays!

    const RestProps:Indexable = {}
      for (const Key of Object.keys(Backing)) {
        if ((Key !== 'children') && (Key !== 'RestProps')) {
          RestProps[Key] = Backing[Key]
        }
      }
    Backing.RestProps = RestProps

  /**** wrap the backing object in a read-only, self-consuming proxy ****/

    return new Proxy(Backing,{
      get (Target:Indexable, Key:string|symbol):unknown {
        if (typeof Key === 'symbol') { return Target[Key as unknown as string] }

        switch (true) {
          case (Key === 'children'):
            return [...Target.children]         // was normalised into an array
          case (Key === 'RestProps'):
            return RestProps       // as a reference (to be modified externally)
          default: {
            const normalisedKey = _normalizedKey(Key)
            delete Target.RestProps[normalisedKey]                                   // self-consuming behaviour
            return Target[normalisedKey]
          }
        }
      },

      set ():boolean {
        throwError('TypeError: "PropSet" is read-only')
      },

      deleteProperty ():boolean {
        throwError('TypeError: "PropSet" is read-only')
      },

      defineProperty ():boolean {
        throwError('TypeError: "PropSet" is read-only')
      },

      has (Target:Indexable, Key:string|symbol):boolean {
        if (typeof Key === 'symbol') { return (Key in Target) }

        switch (true) {
          case (Key === 'children'):  return 'children'  in Target
          case (Key === 'RestProps'): return 'RestProps' in Target
          default: return (_normalizedKey(Key) in Target)
        }
      },

      ownKeys (Target:Indexable):ArrayLike<string|symbol> {
        return Reflect.ownKeys(Target)
      },

      getOwnPropertyDescriptor (Target:Indexable, Key:string|symbol):PropertyDescriptor|undefined {
        const Descriptor = Object.getOwnPropertyDescriptor(Target,Key)
        if (Descriptor != null) {
          Descriptor.writable     = false
          Descriptor.configurable = true                                          // required by the Proxy invariants
        }
        return Descriptor
      }
    })
  }

  function _normalizedKey (Property:string):string {
    return Property.replace(/[-_]/g,'').trim().toLowerCase()
  }

//------------------------------------------------------------------------------
//--                               Acceptables                                --
//------------------------------------------------------------------------------

/**** acceptableValue ****/

  export function acceptableValue (Value:any, Validator:Function):any|undefined {
    expectFunction('Validator',Validator)

    if (Validator(Value) === true) {
      return Value
    } else {
      return undefined
    }
  }

/**** acceptableBoolean ****/

  export function acceptableBoolean (Value:any):boolean|undefined {
    switch (true) {
      case ValueIsBoolean(Value): return Value as boolean
      case (Value === 'false'):   return false
      case (Value === 'true'):    return true
    }
  }

/**** acceptableNumber ****/

// deliberately not based on "coercedNumberSatisfying" - NaN handling differs

  export function acceptableNumber (Value:any):number|undefined {
    if (ValueIsNumber(Value)) { return Value as number }

    if (ValueIsString(Value)) {
      Value = parseFloat(Value as string)
      if (! isNaN(Value)) { return Value as number }
    }
  }

/**** acceptableNumberInRange ****/

  export function acceptableNumberInRange (
    Value:any, Minimum?:number, Maximum?:number,
    withMinimum?:boolean, withMaximum?:boolean
  ):number|undefined {
    return coercedNumberSatisfying(
      Value, (Value:any) => ValueIsNumberInRange(Value,Minimum,Maximum,withMinimum,withMaximum)
    )
  }

