//--                           Localization Support                           --
//------------------------------------------------------------------------------

  type JCL_L10nDictionary = { [Locale:JCL_Locale]:JCL_Dictionary }

  const _globalL10nDictionary = {}

/**** ValueIsDictionary ****/

// a dictionary maps non-empty textlines onto either non-empty textlines
// (plain entries) or records of them (plural categories)

  const _DictionaryTextlinePattern = /^[^\x00-\x1F\x7F\x80-\x9F]+$/

  function ValueIsDictionaryTextline (Value:any):boolean {
    return ValueIsString(Value) && _DictionaryTextlinePattern.test(Value)
  }

  function ValueIsDictionary (Value:any):boolean {
    if (! ValueIsPlainObject(Value)) { return false }

    return Object.entries(Value).every(([ Key,Entry ]) => (
      ValueIsDictionaryTextline(Key) && (
        ValueIsDictionaryTextline(Entry) || (
          ValueIsPlainObject(Entry) &&
          Object.entries(Entry as Indexable).every(([ Category,Text ]) => (
            ValueIsDictionaryTextline(Category) && ValueIsDictionaryTextline(Text)
          ))
        )
      )
    ))
  }

/**** allow/expect[ed]Dictionary ****/

  export const [ allowDictionary,allowedDictionary, expectDictionary,expectedDictionary ] =
    /*@__PURE__*/ ValidatorQuadrupleFor(ValueIsDictionary,'localization dictionary')
/**** _extensibleL10nDictionary ****/

  function _extensibleL10nDictionary (Base:JCL_L10nDictionary):JCL_L10nDictionary {
    const Result = Object.create(Base)
      for (const Locale in Result) {
        Result[Locale] = Object.create(Result[Locale])
      }
    return Result
  }
/**** _extendL10nDictionary ****/

  function _extendL10nDictionary (
    Locale:JCL_Locale, Dictionary:JCL_Dictionary,
    L10nDictionary:JCL_L10nDictionary = _globalL10nDictionary
  ):void {
    expectLocale        ('Locale',Locale)
    expectDictionary('Dictionary',Dictionary)

    Locale = Locale.toLowerCase()
    if (L10nDictionary[Locale] == null) {
      L10nDictionary[Locale] = { ...Dictionary }
    } else {
      Object.assign(L10nDictionary[Locale], Dictionary)
    }
  }

/**** _L10nDictionaryEntry ****/

  function _L10nDictionaryEntry (
    Key:string, Locale:JCL_Locale,
    Dictionary:JCL_L10nDictionary = _globalL10nDictionary
  ):JCL_DictionaryEntry | undefined {
    expectTextline('localization key',Key)
    expectLocale('locale',Locale)

    Locale = Locale.toLowerCase()     // dictionary stores locales in lower case

    let Entry = Dictionary[Locale]?.[Key]                     // at exact locale
    if (Entry != null) { return Entry }

    const Parts = Locale.split('-')                          // at parent locale
    while (Parts.length > 1) {
      Parts.pop()
      Entry = Dictionary[Parts.join('-')]?.[Key]
      if (Entry != null) { return Entry }
    }

    if (Locale !== 'en') {                             // at 'en' as last resort
      Entry = Dictionary['en']?.[Key]
      if (Entry != null) { return Entry }
    }

    return undefined
  }

