/**** _supportedLocaleFor — maps any BCP 47 tag to a supported locale ****/

  function _supportedLocaleFor (Locale:any):JCL_Locale {
    if (typeof Locale !== 'string') { return 'en' }

    let Candidate = Locale.toLowerCase()  // e.g. "de-DE" -> "de-de" -> "de"
    while (true) {
      if (ValueIsLocale(Candidate)) { return Candidate }

      const SeparatorIndex = Candidate.lastIndexOf('-')
      if (SeparatorIndex < 0) { break }
      Candidate = Candidate.slice(0,SeparatorIndex)
    }
    return 'en'                                              // as a last resort
  }

