/**** useOnlineStatus ****/

  export function useOnlineStatus ():boolean {
    const [ isOnline, setIsOnline ] = useState(                     // SSR-ready
      () => typeof navigator !== 'undefined' ? navigator.onLine : true
    )

    useEffect(() => {
      const ExitController = new AbortController()

      const handleOnline  = () => setIsOnline(true)
      const handleOffline = () => setIsOnline(false)

      window.addEventListener('online', handleOnline,  { signal:ExitController.signal })
      window.addEventListener('offline',handleOffline, { signal:ExitController.signal })

      return () => ExitController.abort()
    }, [])

    return isOnline
  }

/**** useWindowSize ****/

  export function useWindowSize ():{ Width:number,Height:number } {
    const [ Size, setSize ] = useState(() => ({                     // SSR-ready
        Width:  typeof window !== 'undefined' ? window.innerWidth  : 0,
        Height: typeof window !== 'undefined' ? window.innerHeight : 0,
    }))

    const RAFRequest = useRef<number>(0)

    const handleResize = useCallback(() => {
      cancelAnimationFrame(RAFRequest.current)
      RAFRequest.current = requestAnimationFrame(() => {
        setSize({ Width:window.innerWidth, Height:window.innerHeight })
      })
    }, [])

    useEffect(() => {
      window.addEventListener('resize', handleResize)
      return () => {
        window.removeEventListener('resize', handleResize)
        cancelAnimationFrame(RAFRequest.current)
      }
    }, [ handleResize ])

    return Size
  }/**** useRerenderer ****/

  export function useRerenderer ():() => void {
    const [ _,setState ] = useState({})

    const  rerender = useCallback(() => setState({}), [])
    return rerender
  }

/**** useCustomization — subscribe to state changes inside components ****/

  export function useCustomization ():JCL_CustomizationContext {
    const Context = useContext(CustomizationContext)
    if (Context == null) throwError(
      'InvalidContext: "useCustomization" must only be used inside a ' +
      '"JCL_Applet", "JCL_Overlay", "JCL_Dialog" or "JCL_Customizable"'
    )
    return Context
  }

/**** useI18n — returns localised formatting and translation utilities ****/

  type JCL_i18n = {                                        // just to remain DRY
    Locale:   JCL_Locale,
    Direction:JCL_Direction,
    Currency: string,

    localized:(Key:string, Vars?:Indexable, Count?:number) => string,

    formattedNumber:      (Value:number, Options?:Intl.NumberFormatOptions) => string,
    formattedDate:        (Value:Date,   Options?:Intl.DateTimeFormatOptions) => string,
    formattedRelativeDate:(Value:number, Unit:Intl.RelativeTimeFormatUnit, Options?:Intl.RelativeTimeFormatOptions) => string,
    formattedCurrency:    (Amount:number, Options?:Intl.NumberFormatOptions) => string,
  }

  export function useI18n ():JCL_i18n {
    return _useI18n (useCustomization())
  }

  function _useI18n (Customization:JCL_CustomizationContext):JCL_i18n {
    const { Locale,Direction, [$L10nDictionary]:L10nDictionary } = Customization
    const Currency = _CurrencyForLocale(Locale)

  /**** localized — look up a dictionary key with optional vars + plurals ****/

    function localized (Key:string, Vars?:Indexable, Count?:number):string {
      const Entry = _L10nDictionaryEntry(Key,Locale,L10nDictionary)
      if (Entry == null) { return Key }              // fallback: return the key

      let Template:string
      if (typeof Entry === 'string') {
        Template = Entry
      } else {
        const PluralCategory:Intl.LDMLPluralRule =
          _PluralRulesForLocale(Locale).select(Count ?? 0)
        Template = Entry[PluralCategory] ?? Entry['other'] ?? Key
      }

      return (Vars == null ? Template : _interpolatedText(Template,Vars))
    }

  /**** formattedNumber — locale-aware number formatting ****/

    function formattedNumber (
      Value:number, Options?:Intl.NumberFormatOptions
    ):string {
      return _NumberFormatForLocale(Locale,Options).format(Value)
    }

  /**** formattedDate — locale-aware date/time formatting ****/

    function formattedDate (
      Value:Date, Options?:Intl.DateTimeFormatOptions
    ):string {
      return _DateTimeFormatForLocale(Locale,Options).format(Value)
    }

  /**** formattedRelativeDate — locale-aware relative time formatting ****/

    function formattedRelativeDate (
      Value:number,
      Unit:Intl.RelativeTimeFormatUnit,
      Options?:Intl.RelativeTimeFormatOptions
    ):string {
      return _relativeTimeFormatForLocale(Locale,Options).format(Value,Unit)
    }

  /**** formattedCurrency — locale-aware currency formatting ****/

    function formattedCurrency (
      Amount:number, Options?:Intl.NumberFormatOptions
    ):string {
      return _NumberFormatForLocale(Locale, {
        style:'currency', currency:Currency, ...Options,
      }).format(Amount)
    }

    return {
      Locale, Direction, Currency,
      localized,
      formattedNumber, formattedDate, formattedRelativeDate, formattedCurrency,
    }
  }

/**** useConfiguration (Configuration is an object of objects) ****/

  export function useConfiguration (
    initialConfiguration:Indexable|Function = {}
  ):[Indexable,Function] {
    if (
      ! ValueIsFunction(initialConfiguration) &&
      ! ValueIsPlainObject(initialConfiguration)
    ) throwError(
      'InvalidArgument:the given initial configuration is neither a plain ' +
      'object nor a function'
    )

    const ConfigurationRef = useRef<Indexable>(undefined!)
    if (ConfigurationRef.current == null) {
      if (ValueIsFunction(initialConfiguration)) {
        initialConfiguration = executedCallback(
          'component callback "initialConfiguration"', initialConfiguration as Function
        )

        if (! ValueIsPlainObject(initialConfiguration)) throwError(
          'InvalidArgument:the result of the initial configuration callback is ' +
          'not a plain object'
        )
      }

      ConfigurationRef.current = { ...initialConfiguration }
    }           // *C* a deeper copy may be better, but perhaps not "deepCopyOf"

  /**** "configure" merges two levels deep ****/

    const configure = useCallback((ChangeSet:Indexable) => {
      allowPlainObject('configuration change set',ChangeSet)
      if (ChangeSet == null) { return }

      for (const [ Key,Value ] of Object.entries(ChangeSet)) {
        if (Value === undefined) {
          delete ConfigurationRef.current[Key]
        } else {
          if (ValueIsPlainObject(Value)) {
            if (ValueIsPlainObject(ConfigurationRef.current[Key])) {
              Object.assign(ConfigurationRef.current[Key],Value)
            } else {
              ConfigurationRef.current[Key] = { ...Value }
            }
          } else {
            throwError(
              'InvalidArgument: configuration[' + quoted(Key) + '] is no ' +
              'plain JavaScript object'
            )
          }
        }
      }
    },[])

  /**** return current configuration and update function ****/

    return [ ConfigurationRef.current,configure ]
  }

//----------------------------------------------------------------------------//
//                                useDragging                                 //
//----------------------------------------------------------------------------//

/* Usage:
  const handlePointerDown = useDragging({
    ViewRef:..., Container:..., onlyFrom:..., neverFrom:...,
    onDragStart:       (dx,dy, x,y, Event) => console.log('Start:', dx,dy, x,y),
    onDragContinuation:(dx,dy, x,y, Event) => console.log('Move :', dx,dy, x,y),
    onDragFinish:      (dx,dy, x,y, Event) => console.log('End  :', dx,dy, x,y),
    onDragCancellation:(dx,dy, x,y, Event) => console.log('Cancel:',dx,dy, x,y),
  })

  html`<... onPointerDown=${handlePointerDown} .../>`
*/

  export type JCL_DragHandler = (dx:number,dy:number, x:number,y:number, Event:PointerEvent|null) => void

/**** global cursor override while dragging ****/

  // while a pointer is captured, browsers show the cursor of the *capturing*
  // element - the following override preserves the cursor of the element the
  // drag was started from (e.g. "se-resize" of a resizer) during the drag.
  // Since only a single drag can be active at a time, the override is kept in
  // a module-level singleton - this way, *any* cleanup path can remove even an
  // override that another instance failed to remove.
  // "_setDragCursor" is also used by "usePointerDragSupport" which changes
  // the cursor *during* a drag depending on the current drop effect

  let _DragCursorStyle:HTMLStyleElement|undefined

  function _setDragCursor (Cursor:string):void {
    if (typeof document === 'undefined') { return }

    if (_DragCursorStyle == null) {
      _DragCursorStyle = document.createElement('style')
      document.head.appendChild(_DragCursorStyle)
    }
    _DragCursorStyle.textContent = '* { cursor:' + Cursor + ' !important }'
  }

  function _installDragCursorFor (Target:HTMLElement):void {
    if (typeof document === 'undefined') { return }
    _removeDragCursor()                                      // just to be safe

    const Cursor = getComputedStyle(Target).cursor
    if ((Cursor === '') || (Cursor === 'auto')) { return }

    _setDragCursor(Cursor)
  }

  function _removeDragCursor ():void {
    _DragCursorStyle?.remove()
    _DragCursorStyle = undefined
  }

/**** shared argument checks and helpers of all drag recognizers ****/

  // used by "useDragging", "useClickDragging" and "usePointerDragSupport"

  function expectContainerSpec (Container:any):void {
    if ((Container != null) && ! ValueIsTextline(Container) && ! (Container instanceof HTMLElement) && ! ValueIsFunction(Container)) throwError(
      'InvalidArgument: "Container" is neither a CSS selector nor an HTML element or a function'
    )
  }

  function expectSelectorOrElement (Name:string, Value:any):void {
    if ((Value != null) && ! ValueIsTextline(Value) && ! (Value instanceof HTMLElement)) throwError(
      `InvalidArgument: "${Name}" is neither a CSS selector nor an HTML element`
    )
  }

  function resolvedContainerFor (
    View:HTMLElement, Container:any
  ):HTMLElement|undefined {
    switch (true) {
      case Container == null:
        return (View.parentElement ?? undefined) as HTMLElement|undefined
      case Container === 'self':
        return View as HTMLElement
      case ValueIsTextline(Container):
        return View.parentElement?.closest(Container as string) as HTMLElement|undefined
      case ValueIsFunction(Container): {
        const ContainerElement = (Container as Function)() as HTMLElement
        return (
          ContainerElement instanceof HTMLElement ? ContainerElement : undefined
        )
      }
      default:
        return Container as HTMLElement
    }
  }

  function isPrimaryPointer (Event:PointerEvent):boolean {
    switch (Event.pointerType) {
      case 'mouse': return (Event.buttons === 1)
      case 'touch': return Event.isPrimary
      case 'pen':   return (Event.buttons === 1)
      default:      return true
    }
  }

/**** useDragging ****/

  export function useDragging ({
    ViewRef, Container, onlyFrom, neverFrom,
    onDragStart, onDragContinuation, onDragFinish, onDragCancellation
  }:{
    ViewRef:any,
    Container?:JCL_Selector|HTMLElement|Function,
    onlyFrom?: JCL_Selector|HTMLElement,
    neverFrom?:JCL_Selector|HTMLElement,
    onDragStart?:       JCL_DragHandler,
    onDragContinuation?:JCL_DragHandler,
    onDragFinish?:      JCL_DragHandler,
    onDragCancellation?:JCL_DragHandler,
  }):Function|undefined {                 // returns handler for "onPointerDown"
    expectPreactRef('ViewRef',ViewRef)
    expectContainerSpec(Container)
    expectSelectorOrElement ('onlyFrom',onlyFrom)
    expectSelectorOrElement('neverFrom',neverFrom)
    allowFunction       ('"onDragStart" callback',onDragStart)
    allowFunction('"onDragContinuation" callback',onDragContinuation)
    allowFunction      ('"onDragFinish" callback',onDragFinish)
    allowFunction('"onDragCancellation" callback',onDragCancellation)

    const RecognizerMayDrag = (
      (onDragStart  != null) && (onDragContinuation != null) &&
      (onDragFinish != null) && (onDragCancellation != null)
    )

    type DragCallbacks = {
      onDragStart?:       JCL_DragHandler,
      onDragContinuation?:JCL_DragHandler,
      onDragFinish?:      JCL_DragHandler,
      onDragCancellation?:JCL_DragHandler,
    }
    const Callbacks            = useRef<DragCallbacks>(); Callbacks.current            = { onDragStart, onDragContinuation, onDragFinish, onDragCancellation }
    const RecognizerMayDragRef = useRef<boolean>(false);  RecognizerMayDragRef.current = RecognizerMayDrag

  /**** initialize dragging ****/

    const ContainerRef  = useRef<HTMLElement|undefined>()
    const StartPosition = useRef<{ x:number; y:number } | undefined>()
    const isDragging    = useRef<boolean>(false)

  /**** this hook requires an existing View (appears after rendering only) ****/

    useEffect(() => {
      if (ViewRef.current == null) { return }   // that would be strange, though
      ContainerRef.current = resolvedContainerFor(ViewRef.current,Container)
    },[ ViewRef.current /* Container */ ])// well, *never* change the Container!

    useEffect(() => {
      return () => {
        window.removeEventListener('pointermove',  onPointerMove)
        window.removeEventListener('pointerup',    onPointerUp)
        window.removeEventListener('pointercancel',onPointerCancel)
        window.removeEventListener('blur',         onWindowBlur)

        if (isDragging.current) {              // unmounted while still dragging
          isDragging.current = false
          _removeDragCursor()
        }
      }
    },[])

  /**** onPointerDown ****/

    const onPointerDown = useCallback((Event:PointerEvent) => {
      if (! (Event.target instanceof HTMLElement)) { return }
      if (! isPrimaryPointer(Event))               { return }

      if (! RecognizerMayDrag)          { return }
      if (ContainerRef.current == null) { return }

      if ((onlyFrom  != null) && ! matchesSelector(Event.target,onlyFrom))  { return }
      if ((neverFrom != null) &&   matchesSelector(Event.target,neverFrom)) { return }

      window.addEventListener('pointermove',  onPointerMove)
      window.addEventListener('pointerup',    onPointerUp)
      window.addEventListener('pointercancel',onPointerCancel)
      window.addEventListener('blur',         onWindowBlur)

      ViewRef.current.setPointerCapture?.(Event.pointerId)
      _installDragCursorFor(Event.target)

      const ContainerElement = ContainerRef.current as HTMLElement   // never undef.
      const ContainerBox     = ContainerElement.getBoundingClientRect()

      const StartX = Event.clientX - ContainerBox.left + ContainerElement.scrollLeft
      const StartY = Event.clientY - ContainerBox.top  + ContainerElement.scrollTop

      StartPosition.current = { x:StartX, y:StartY }
      isDragging.current    = true

      executeCallback('useDragging callback "onDragStart"', Callbacks.current?.onDragStart, 0,0, StartX,StartY, Event)
    },[ ViewRef, RecognizerMayDrag, onlyFrom, neverFrom ])

  /**** onPointerMove ****/

    const onPointerMove = useCallback((Event:PointerEvent) => {
      if (isDragging.current === false) { return }

      if ((Event.pointerType === 'mouse') && (Event.buttons === 0)) {
        finishDragging(Event,false)     // the "pointerup" was somehow missed -
        return                          // e.g. swallowed by another handler
      }

      if (ContainerRef.current == null) { return }
      executeCallback('useDragging callback "onDragContinuation"', Callbacks.current?.onDragContinuation, ...CallbackArguments(Event))
    },[])   // once created, never changed (important for "removeEventListener")

  /**** onPointerUp ****/

    const onPointerUp = useCallback((Event:PointerEvent) => {
      finishDragging(Event,false)
    },[])   // once created, never changed (important for "removeEventListener")

  /**** onPointerCancel ****/

    const onPointerCancel = useCallback((Event:PointerEvent) => {
      finishDragging(Event,true)
    },[])   // once created, never changed (important for "removeEventListener")

  /**** onWindowBlur — cancels a drag when the window loses focus ****/

    const onWindowBlur = useCallback(() => {
      finishDragging(null,true)
    },[])   // once created, never changed (important for "removeEventListener")

  /**** finishDragging ****/

    const finishDragging = useCallback((Event:PointerEvent|null, cancelled:boolean) => {
      if (isDragging.current === false) { return }

      isDragging.current = false

      _removeDragCursor()

      if ((Event != null) && ViewRef.current?.hasPointerCapture?.(Event.pointerId)) {
        ViewRef.current.releasePointerCapture(Event.pointerId) // release capture
      }

      window.removeEventListener('pointermove',  onPointerMove)
      window.removeEventListener('pointerup',    onPointerUp)
      window.removeEventListener('pointercancel',onPointerCancel)
      window.removeEventListener('blur',         onWindowBlur)

      if (cancelled) {
        executeCallback('useDragging callback "onDragCancellation"', Callbacks.current?.onDragCancellation, 0,0, StartPosition.current!.x,StartPosition.current!.y, Event)
        return
      }

      if ((ContainerRef.current != null) && RecognizerMayDragRef.current) {
        executeCallback('useDragging callback "onDragFinish"', Callbacks.current?.onDragFinish, ...CallbackArguments(Event as PointerEvent))
      }
    },[])       // once created, never changed — mutable state accessed via refs

  /**** CallbackArguments (plain function) ****/

    function CallbackArguments (
      Event:PointerEvent
    ):[ dx:number,dy:number, x:number,y:number, Event:PointerEvent ] {
      const Container = ContainerRef.current
      if (Container == null) { return [ 0,0,0,0, Event ] }

      const ContainerBox = Container.getBoundingClientRect()

      const x = Event.clientX - ContainerBox.left + Container.scrollLeft
      const y = Event.clientY - ContainerBox.top  + Container.scrollTop

      const dx = x - StartPosition.current!.x
      const dy = y - StartPosition.current!.y

      return [ dx,dy, x,y, Event ]
    }

  /**** matchesSelector (plain function) ****/

    function matchesSelector (
      Element:HTMLElement, Selector:JCL_Selector|HTMLElement|undefined
    ):boolean {              // also matches when "Element" is nested *inside* a
      switch (true) {                        // matching element (e.g. the title
        case (Selector == null):                       // span inside a titlebar)
          return true
        case (typeof Selector === 'string'):
          return (Element.closest(Selector) != null)
        default:
          return (Selector as HTMLElement).contains(Element)
      }
    }

    return (RecognizerMayDrag ? onPointerDown : undefined)
  }
