/* Usage:
  const DataDragProps = useDataDragSupport('{"id":42}', 'application/json', {
    Effect:       'move',
    draggedGhost: (Event) => {
      const Ghost = document.createElement('div')
      Ghost.className = 'drag-ghost'
      Ghost.textContent = 'Moving...'
      return Ghost
    },
    onDropped: (Effect,Event) => { if (Effect === 'move') removeItem(42) },
  })

  html`<div ...${DataDragProps}>Drag me</>`
*/

/**** JCL_DataDropEffect — allowed values for DataTransfer.effectAllowed ****/

  export const JCL_DataDropEffects = [
    'none','copy','copyLink','copyMove','link','linkMove','move','all',
  ] as const
  export type  JCL_DataDropEffect  = typeof JCL_DataDropEffects[number]

/**** useDataDragSupport ****/

  export type JCL_DataDragSupportCallbacks = {
    draggedGhost?: (Event:DragEvent) => HTMLElement|null,
    onDropped?:    (Effect:string, Event:DragEvent) => void,
  }

  export function useDataDragSupport (
    Data:string, MIMEType:string, { Effect, draggedGhost, onDropped, }:{
      Effect?:      JCL_DataDropEffect,
      draggedGhost?:(Event:DragEvent) => HTMLElement|null,
      onDropped?:   (Effect:string, Event:DragEvent) => void,
    } = {}
  ):{ draggable:true, onDragStart:Function, onDragEnd:Function } {
    expectString                    ('Data',Data)
    expectMIMEType              ('MIMEType',MIMEType)
    allowOneOf                    ('Effect',Effect, [...JCL_DataDropEffects])
    allowFunction('"draggedGhost" callback',draggedGhost)
    allowFunction   ('"onDropped" callback',onDropped)

  /**** stable refs — always current without recreating handlers ****/

    const DataRef     = useRef<string>(Data);                     DataRef.current     = Data
    const MIMETypeRef = useRef<string>(MIMEType);                 MIMETypeRef.current = MIMEType
    const EffectRef   = useRef<JCL_DataDropEffect|undefined>();   EffectRef.current   = Effect
    const CallbackRef = useRef<JCL_DataDragSupportCallbacks>({}); CallbackRef.current = { draggedGhost, onDropped }

  /**** onDragStart ****/

    const onDragStart = useCallback((Event:DragEvent) => {
      const DataTransfer = Event.dataTransfer
      if (DataTransfer == null) { return }

      DataTransfer.setData(MIMETypeRef.current, DataRef.current)
      if (EffectRef.current != null) { DataTransfer.effectAllowed = EffectRef.current }

      const Ghost = executedCallback('useDataDragSupport callback "draggedGhost"', CallbackRef.current.draggedGhost, Event) ?? null
      if (Ghost != null) {
        document.body.appendChild(Ghost)
        DataTransfer.setDragImage(Ghost, Ghost.offsetWidth/2, Ghost.offsetHeight/2)
        requestAnimationFrame(() => Ghost.remove())
      }

    }, [])      // once created, never changed — mutable state accessed via refs

  /**** onDragEnd ****/

    const onDragEnd = useCallback((Event:DragEvent) => {
      const droppedEffect = Event.dataTransfer?.dropEffect ?? 'none'
      if (droppedEffect !== 'none') {
        executeCallback('useDataDragSupport callback "onDropped"', CallbackRef.current.onDropped, droppedEffect, Event)
      }
    }, [])      // once created, never changed — mutable state accessed via refs

  /**** return drag props to spread onto the draggable element ****/

    return { draggable:true, onDragStart, onDragEnd }
  }
