/* Usage:
  const handlePointerDown = usePointerDragSupport({
    ViewRef:..., Container:..., onlyFrom:..., neverFrom:..., Threshold:4,
    data: myItem, allowedEffects: ['move','copy'],
    GrabCursor:'grab', GrabbedCursor:'grabbing',
    onClick:           (x,y, Event)                                   => ...,
    onDragStart:       (dx,dy, x,y, Event)                            => ...,
    onDragContinuation:(dx,dy, x,y, Event)                            => ...,
    onDragFinish:      (dx,dy, x,y, Event)                            => ...,
    onDragCancellation:(dx,dy, x,y, Event)                            => ...,
    onDrop:            (dx,dy, x,y, Event, DroppedOnto, chosenEffect) => ...,
  })

  - ghost elements must have "pointer-events:none" to not block "ElementFromPoint"
  - when Alt is held and 'copy' is in allowedEffects, only 'copy' is offered

  html`<... onPointerDown=${handlePointerDown} .../>`
*/

/**** _validDropEffects — accepted values for JCL_DropEffect ****/

  export const JCL_PointerDropEffects = [ 'move', 'copy', 'alias' ]
  export type  JCL_PointerDropEffect  = JCL_DropEffect  // identical to JCL_DropEffect

/**** usePointerDragSupport ****/

  export type JCL_PointerDragDropHandler = (
    dx:number, dy:number, x:number, y:number,
    Event:PointerEvent, DroppedOnto:HTMLElement, chosenEffect:JCL_DropEffect
  ) => void

  export function usePointerDragSupport ({
    ViewRef, Container, onlyFrom, neverFrom, Threshold = 4,
    Data, allowedEffects,
    GrabCursor = 'grab', GrabbedCursor = 'grabbing',
    onClick, onDragStart, onDragContinuation, onDragFinish, onDragCancellation, onDrop,
  }:{
    ViewRef:            any,
    Container?:         JCL_Selector|HTMLElement|Function,
    onlyFrom?:          JCL_Selector|HTMLElement,
    neverFrom?:         JCL_Selector|HTMLElement,
    Threshold?:         number,
    Data?:              unknown,
    allowedEffects?:    JCL_PointerDropEffect[],
    GrabCursor?:        string,
    GrabbedCursor?:     string,
    onClick?:           JCL_ClickHandler,
    onDragStart?:       JCL_DragHandler,
    onDragContinuation?:JCL_DragHandler,
    onDragFinish?:      JCL_DragHandler,
    onDragCancellation?:JCL_DragHandler,
    onDrop?:            JCL_PointerDragDropHandler,
  }):Function|undefined {
    expectPreactRef('preact component reference',ViewRef)
    expectContainerSpec(Container)                     // s. "useDragging" for...
    expectSelectorOrElement ('onlyFrom',onlyFrom)      // ...these shared helpers
    expectSelectorOrElement('neverFrom',neverFrom)
    allowCardinal              ('drag threshold',Threshold)
    allowListSatisfying         ('allowedEffects',allowedEffects,(Value:any) => ValueIsOneOf(Value,JCL_PointerDropEffects),'list of drop effects',1)
    allowTextline      ('"GrabCursor" CSS cursor',GrabCursor)
    allowTextline   ('"GrabbedCursor" CSS cursor',GrabbedCursor)
    allowFunction           ('"onClick" callback',onClick)
    allowFunction       ('"onDragStart" callback',onDragStart)
    allowFunction('"onDragContinuation" callback',onDragContinuation)
    allowFunction      ('"onDragFinish" callback',onDragFinish)
    allowFunction('"onDragCancellation" callback',onDragCancellation)
    allowFunction            ('"onDrop" callback',onDrop)

    const RecognizerMayClick = (onClick != null)
    const RecognizerMayDrag  = (
      (onDragStart  != null) && (onDragContinuation != null) &&
      (onDragFinish != null) && (onDragCancellation != null)
    )
    const RecognizerIsActive = RecognizerMayClick || RecognizerMayDrag

  /**** refs for stable callbacks (always up-to-date without recreating handlers) ****/

    type DragSupportCallbacks = {
      onClick?:           JCL_ClickHandler,
      onDragStart?:       JCL_DragHandler,
      onDragContinuation?:JCL_DragHandler,
      onDragFinish?:      JCL_DragHandler,
      onDragCancellation?:JCL_DragHandler,
      onDrop?:            JCL_PointerDragDropHandler,
    }
    const Callbacks             = useRef<DragSupportCallbacks>(); Callbacks.current             = { onClick, onDragStart, onDragContinuation, onDragFinish, onDragCancellation, onDrop }
    const RecognizerMayClickRef = useRef<boolean>(false);         RecognizerMayClickRef.current = RecognizerMayClick
    const RecognizerMayDragRef  = useRef<boolean>(false);         RecognizerMayDragRef.current  = RecognizerMayDrag
    const ThresholdRef          = useRef<number>(Threshold);      ThresholdRef.current          = Threshold
    const DataRef               = useRef<unknown>(Data);          DataRef.current               = Data

    const EffectList:JCL_DropEffect[] = allowedEffects ?? [ 'move' ]
    const allowedEffectsRef  = useRef<JCL_DropEffect[]>(EffectList); allowedEffectsRef.current  = EffectList
    const GrabbedCursorRef   = useRef<string>(GrabbedCursor);        GrabbedCursorRef.current   = GrabbedCursor

  /**** context — accessed via ref inside once-created handlers ****/

    const { closestDropTarget } = useContext(JCL_PointerDnDContext)
    const closestDropTargetRef  = useRef(closestDropTarget); closestDropTargetRef.current = closestDropTarget

  /**** dragging state ****/

    const ContainerRef          = useRef<HTMLElement|undefined>()
    const StartPosition         = useRef<{ x:number; y:number } | undefined>()
    const StartEvent            = useRef<PointerEvent|undefined>()
    const isDragging            = useRef<boolean>(false)
    const hasMoved              = useRef<boolean>(false)
    const currentTarget         = useRef<HTMLElement|undefined>()
    const currentEntry          = useRef<JCL_DropTargetEntry|undefined>()
    const currentChosenEffect   = useRef<JCL_DropEffect|undefined>()

  /**** Container resolution (runs after render) ****/

    useEffect(() => {
      if (ViewRef.current == null) { return }
      ContainerRef.current = resolvedContainerFor(ViewRef.current,Container)
    },[ ViewRef.current /* Container */ ])// well, *never* change the Container!

    useEffect(() => {
      if (! RecognizerMayDrag || ViewRef.current == null) { return }
      ViewRef.current.style.cursor = GrabCursor
      return () => {
        if (ViewRef.current != null) { ViewRef.current.style.cursor = '' }
      }
    },[ ViewRef, RecognizerMayDrag, GrabCursor ])

    useEffect(() => {
      return () => {
        window.removeEventListener('pointermove',  onPointerMove)
        window.removeEventListener('pointerup',    onPointerUp)
        window.removeEventListener('pointercancel',onPointerCancel)

        if (isDragging.current) {              // unmounted while still dragging
          isDragging.current = false
          _removeDragCursor()
        }
      }
    },[])

  /**** onPointerDown ****/

    const onPointerDown = useCallback((Event:PointerEvent) => {
      if (! (Event.target instanceof HTMLElement)) { return }
      if (! isPrimaryPointer(Event))               { return }

      if (! RecognizerIsActive)         { return }
      if (ContainerRef.current == null) { return }

      if ((onlyFrom  != null) && ! matchesSelector(Event.target,onlyFrom))  { return }
      if ((neverFrom != null) &&   matchesSelector(Event.target,neverFrom)) { return }

      window.addEventListener('pointermove',  onPointerMove)
      window.addEventListener('pointerup',    onPointerUp)
      window.addEventListener('pointercancel',onPointerCancel)

      ViewRef.current.setPointerCapture?.(Event.pointerId)

      const ContainerElement = ContainerRef.current as HTMLElement
      const ContainerBox     = ContainerElement.getBoundingClientRect()

      const StartX = Event.clientX - ContainerBox.left + ContainerElement.scrollLeft
      const StartY = Event.clientY - ContainerBox.top  + ContainerElement.scrollTop

      StartPosition.current       = { x:StartX, y:StartY }
      StartEvent.current          = Event
      isDragging.current          = true
      hasMoved.current            = false
      currentTarget.current       = undefined
      currentEntry.current        = undefined
      currentChosenEffect.current = undefined
    },[ ViewRef, RecognizerIsActive, onlyFrom, neverFrom ])

  /**** onPointerMove ****/

    const onPointerMove = useCallback((Event:PointerEvent) => {
      if (! isDragging.current)         { return }
      if (ContainerRef.current == null) { return }

      const [ dx,dy, x,y ] = CallbackArguments(Event)

      if (! hasMoved.current) {
        if (Math.sqrt(dx*dx + dy*dy) < ThresholdRef.current) { return }
        hasMoved.current = true
        if (RecognizerMayDragRef.current) {
          Callbacks.current!.onDragStart?.(0,0, StartPosition.current!.x,StartPosition.current!.y, StartEvent.current!)
        }
      }

      if (RecognizerMayDragRef.current) {
        const effectiveAllowedEffects:JCL_DropEffect[] = (
          Event.altKey && allowedEffectsRef.current.includes('copy')
        ) ? [ 'copy' ]
          : allowedEffectsRef.current

        const Hit              = closestDropTargetRef.current(Event.clientX, Event.clientY)
        const newTargetElement = Hit?.[0]
        const newEntry         = Hit?.[1]

        if (newTargetElement !== currentTarget.current) {
          if (currentTarget.current != null) {
            currentEntry.current!.onLeave?.(DataRef.current)
          }
          const chosenEffect = (newTargetElement != null)
            ? newEntry!.accepts(DataRef.current, effectiveAllowedEffects)
            : false
          if (chosenEffect !== false) {
            newEntry!.onEnter?.(DataRef.current, chosenEffect, x, y)
            currentTarget.current       = newTargetElement
            currentEntry.current        = newEntry
            currentChosenEffect.current = chosenEffect
          } else {
            currentTarget.current       = undefined
            currentEntry.current        = undefined
            currentChosenEffect.current = undefined
          }
        } else if (currentTarget.current != null) {
          const chosenEffect = currentEntry.current!.accepts(DataRef.current, effectiveAllowedEffects)
          if (chosenEffect !== false) {
            currentChosenEffect.current = chosenEffect
            currentEntry.current!.onOver?.(DataRef.current, chosenEffect, x, y)
          } else {
            currentEntry.current!.onLeave?.(DataRef.current)
            currentTarget.current       = undefined
            currentEntry.current        = undefined
            currentChosenEffect.current = undefined
          }
        }

        _setDragCursor(               // shares the singleton of "useDragging"
          currentTarget.current != null               ? _cursorForEffect(currentChosenEffect.current) :
          _isWithinView(Event.clientX, Event.clientY) ? GrabbedCursorRef.current                      :
          'no-drop'
        )

        Callbacks.current!.onDragContinuation?.(dx,dy, x,y, Event)
      }
    },[])   // once created, never changed (important for "removeEventListener")

  /**** onPointerUp ****/

    const onPointerUp = useCallback((Event:PointerEvent) => {
      finishDragging(Event,false)
    },[])   // once created, never changed (important for "removeEventListener")

  /**** onPointerCancel ****/

    const onPointerCancel = useCallback((Event:PointerEvent) => {
      finishDragging(Event,true)
    },[])   // once created, never changed (important for "removeEventListener")

  /**** finishDragging ****/

    const finishDragging = useCallback((Event:PointerEvent, cancelled:boolean) => {
      if (! isDragging.current) { return }

      isDragging.current = false

      if (ViewRef.current?.hasPointerCapture?.(Event.pointerId)) {
        ViewRef.current.releasePointerCapture(Event.pointerId)   // release capture
      }

      window.removeEventListener('pointermove',  onPointerMove)
      window.removeEventListener('pointerup',    onPointerUp)
      window.removeEventListener('pointercancel',onPointerCancel)

      if (hasMoved.current) {
        _removeDragCursor()
      }

      if (cancelled) {
        if (hasMoved.current && RecognizerMayDragRef.current) {
          if (currentTarget.current != null) {
            currentEntry.current!.onLeave?.(DataRef.current)
            currentTarget.current       = undefined
            currentEntry.current        = undefined
            currentChosenEffect.current = undefined
          }
          Callbacks.current!.onDragCancellation?.(0,0, StartPosition.current!.x,StartPosition.current!.y, Event)
        }
        hasMoved.current = false
        return
      }

      if (hasMoved.current) {
        if (RecognizerMayDragRef.current) {
          if (currentTarget.current != null) {
            const Target        = currentTarget.current
            const Entry         = currentEntry.current!
            const chosenEffect  = currentChosenEffect.current!
            const TargetRect    = Target.getBoundingClientRect()
            const TargetX       = Event.clientX - TargetRect.left + Target.scrollLeft
            const TargetY       = Event.clientY - TargetRect.top  + Target.scrollTop
            currentTarget.current       = undefined
            currentEntry.current        = undefined
            currentChosenEffect.current = undefined
            Entry.onDrop?.(DataRef.current, chosenEffect, TargetX, TargetY)
            Callbacks.current!.onDrop?.(0,0, StartPosition.current!.x,StartPosition.current!.y, Event, Target, chosenEffect)
          } else {
            Callbacks.current!.onDragFinish?.apply(null,CallbackArguments(Event))
          }
        }
      } else {
        if (RecognizerMayClickRef.current && (ContainerRef.current != null)) {
          const ContainerElement = ContainerRef.current
          const ContainerBox     = ContainerElement.getBoundingClientRect()
          const x = Event.clientX - ContainerBox.left + ContainerElement.scrollLeft
          const y = Event.clientY - ContainerBox.top  + ContainerElement.scrollTop
          Callbacks.current!.onClick?.(x,y, Event)
        }
      }
      hasMoved.current = false
    },[])       // once created, never changed — mutable state accessed via refs

  /**** CallbackArguments (plain function) ****/

    function CallbackArguments (
      Event:PointerEvent
    ):[ dx:number,dy:number, x:number,y:number, Event:PointerEvent ] {
      const Container = ContainerRef.current
      if (Container == null) { return [ 0,0,0,0, Event ] }

      const ContainerBox = Container.getBoundingClientRect()

      const x  = Event.clientX - ContainerBox.left + Container.scrollLeft
      const y  = Event.clientY - ContainerBox.top  + Container.scrollTop

      const dx = x - StartPosition.current!.x
      const dy = y - StartPosition.current!.y

      return [ dx,dy, x,y, Event ]
    }

  /**** _cursorForEffect (plain function) — maps a drop effect to a CSS cursor ****/

    function _cursorForEffect (Effect:JCL_DropEffect|undefined):string {
      switch (Effect) {
        case 'copy':  return 'copy'
        case 'alias': return 'alias'
        case 'move':  return 'move'
        default:      return GrabbedCursorRef.current
      }
    }

  /**** _isWithinView (plain function) ****/

    function _isWithinView (clientX:number, clientY:number):boolean {
      if (ViewRef.current == null) { return false }
      const Rect = (ViewRef.current as HTMLElement).getBoundingClientRect()
      return (
        (clientX >= Rect.left) && (clientX <= Rect.right) &&
        (clientY >= Rect.top)  && (clientY <= Rect.bottom)
      )
    }

  /**** matchesSelector (plain function) ****/

    function matchesSelector (
      Element:HTMLElement, Selector:JCL_Selector|HTMLElement|undefined
    ):boolean {
      switch (true) {
        case (Selector == null):             return true
        case (typeof Selector === 'string'): return Element.matches(Selector)
        default:                             return Element === Selector
      }
    }

    return (RecognizerIsActive ? onPointerDown : undefined)
  }
