/**** JCL_ErrorIndicator ****/

  export function JCL_ErrorIndicator (PropSet:Indexable):any {
    return safelyRendered(() => {
      ensureErrorIndicatorStyles()

      PropSet = parseablePropSet(PropSet)
        let ErrorToShow   = acceptableValue(PropSet.Error,
          (Value:any) => (Value instanceof Error) || ValueIsText(Value)
        )
        let ErrorResetter = acceptableFunction(PropSet.ErrorResetter)

      switch (true) {
        case ErrorToShow instanceof Error:
          break
        case ValueIsText(ErrorToShow):
          if (/^[^\n]+\n\n[^\n]+/.test(ErrorToShow)) {
            const Title   = ErrorToShow.replace(/\n\n.*$/,'')
            const Message = ErrorToShow.replace(/^[^\n]+\n\n/,'')
            ErrorToShow      = new Error(Message)
            ErrorToShow.name = Title
          } else {
            ErrorToShow      = new Error(ErrorToShow)
            ErrorToShow.name = 'Unexpected Failure'
          }
          break
        default:
          ErrorToShow      = new Error('' + ErrorToShow)
          ErrorToShow.name = 'Unexpected Failure'
      }

      const onClick = ():void => {
console.warn(ErrorToShow)
        window.alert(ErrorMessageFor(ErrorToShow))
      }

      return html`<div class="jcl-error-indicator" onClick=${onClick}/>`
    })
  }

