/**** ErrorMessageFor ****/

  function ErrorMessageFor (ErrorToShow:Error):any {
    let ErrorName    = ErrorToShow.name
    let ErrorMessage = ErrorToShow.message || '(unidentified error)'
    let StackTrace   = ErrorToShow.stack   ?? ''

    const Title   = ErrorName.replace(/([a-z])([A-Z])/g,'$1 $2')
    const Message = ErrorMessage.charAt(0).toUpperCase() + ErrorMessage.slice(1)

    if (StackTrace === '') {
      return `${Title}\n\n${Message}`
    } else {
      return `${Title}\n\n${Message}\n\n${StackTrace}`
    }
  }
/**** PseudoRef ****/

  export function PseudoRef (Value?:any):Indexable {
    return { current:Value }
  }

/**** safelyRendered ****/

// upon its very first invocation, JCL's global initialisation is performed
// as well - this keeps the module free of side effects at load time while
// still setting everything up as soon as the first component is rendered

  let _JCLwasInitialized = false

  export function safelyRendered (Renderer:Function):any {
    if (! _JCLwasInitialized) {
      _JCLwasInitialized = true
      installJCLStylesheet()
      _trackUnhandledRejections()
    }

    expectFunction('rendering function',Renderer)

    const [ Error,resetError ] = useErrorBoundary()
    if (Error != null) {
      const ComponentName = Renderer.name ?? ''
      if (ComponentName.trim() === '') {
        console.warn('rendering error within preact component: ' + Error)
      } else {
        console.warn(
          'rendering error within ' + quoted(ComponentName) + ': ' +
          Error
        )
      }
      return html`<${JCL_ErrorIndicator} Error=${Error} ErrorResetter=${resetError}/>`
    }

    try {
      return Renderer()
    } catch (Signal:any) {
      const ComponentName = Renderer.name ?? ''
      if (ComponentName.trim() === '') {
        console.warn('error while rendering a preact component: ' + Signal)
      } else {
        console.warn(
          'error while rendering component ' + quoted(ComponentName) + ': ' +
          Signal
        )
      }
      return html`<${JCL_ErrorIndicator} Error=${Signal} ErrorResetter=${resetError}/>`
    }
  }
