// based on CodeMirror 6 - all "@codemirror/*" core packages are lazily
// loaded on first use (language support packages were lazy already, see
// note "Language Registry")

  let EditorState:any, Compartment:any                    // @codemirror/state
  let EditorView:any, keymap:any, lineNumbers:any,        // @codemirror/view
      drawSelection:any, highlightSpecialChars:any
  let syntaxHighlighting:any, defaultHighlightStyle:any,  // @codemirror/language
      indentUnit:any, syntaxTree:any, ensureSyntaxTree:any
  let defaultKeymap:any, historyKeymap:any,               // @codemirror/commands
      indentWithTab:any, ChangeHistory:any,
      undoChange:any, redoChange:any
  let setDiagnostics:any, lintGutter:any, linter:any      // @codemirror/lint

  const loadCodeEditorLibraries = memoizedLoader(() => Promise.all([
      loadedLibrary('@codemirror/state'),
      loadedLibrary('@codemirror/view'),
      loadedLibrary('@codemirror/language'),
      loadedLibrary('@codemirror/commands'),
      loadedLibrary('@codemirror/lint')
    ]).then(([
      StateModule, ViewModule, LanguageModule, CommandsModule, LintModule
    ]) => {
      EditorState           = StateModule.EditorState
      Compartment           = StateModule.Compartment

      EditorView            = ViewModule.EditorView
      keymap                = ViewModule.keymap
      lineNumbers           = ViewModule.lineNumbers
      drawSelection         = ViewModule.drawSelection
      highlightSpecialChars = ViewModule.highlightSpecialChars

      syntaxHighlighting    = LanguageModule.syntaxHighlighting
      defaultHighlightStyle = LanguageModule.defaultHighlightStyle
      indentUnit            = LanguageModule.indentUnit
      syntaxTree            = LanguageModule.syntaxTree
      ensureSyntaxTree      = LanguageModule.ensureSyntaxTree

      defaultKeymap         = CommandsModule.defaultKeymap
      historyKeymap         = CommandsModule.historyKeymap
      indentWithTab         = CommandsModule.indentWithTab
      ChangeHistory         = CommandsModule.history
      undoChange            = CommandsModule.undo
      redoChange            = CommandsModule.redo

      setDiagnostics        = LintModule.setDiagnostics
      lintGutter            = LintModule.lintGutter
      linter                = LintModule.linter
    })
  )

  export type JCL_CodeEditorSeverity = 'error'|'warning'|'info'
  export type JCL_CodeEditorError    = {
    Line:number, Column?:number, EndLine?:number, EndColumn?:number,
    Message:string, Severity?:JCL_CodeEditorSeverity
  }
  export type JCL_CodeEditorLanguageLoader   = () => Promise<any>
  export type JCL_CodeEditorLinter           = (Code:string) =>
    JCL_CodeEditorError[] | Promise<JCL_CodeEditorError[]>
  export type JCL_onCodeEditorValueChange     = (Value:string) => void
  export type JCL_onCodeEditorSelectionChange = (from:number, to:number) => void

/**** registry for languages supported by the CodeEditor ****/

  const CodeEditorLanguageRegistry:Indexable = Object.create(null)

  export function registerCodeEditorLanguage (
    Name:string, Loader:JCL_CodeEditorLanguageLoader
  ):void {
    expectTextline('language name',Name)
    expectFunction('language support loader',Loader)

    CodeEditorLanguageRegistry[Name.toLowerCase()] = Loader
  }

/**** built-in languages (lazily loaded on first use) ****/

// each entry names its module, the factory export to call and (optionally)
// the factory arguments - computed specifiers are fine here, since JCL is
// used without any build step and "loadedLibrary" caches every module

  const _builtInLanguages:Indexable = {
    javascript:[ '@codemirror/lang-javascript','javascript' ],
    typescript:[ '@codemirror/lang-javascript','javascript', { typescript:true } ],
    html:      [ '@codemirror/lang-html',      'html' ],
    css:       [ '@codemirror/lang-css',       'css' ],
    json:      [ '@codemirror/lang-json',      'json' ],
    markdown:  [ '@codemirror/lang-markdown',  'markdown' ],
    python:    [ '@codemirror/lang-python',    'python' ],
    xml:       [ '@codemirror/lang-xml',       'xml' ],
    java:      [ '@codemirror/lang-java',      'java' ],
    yaml:      [ '@codemirror/lang-yaml',      'yaml' ],
  }

  let _builtInLanguagesRegistered = false

  function _ensureBuiltInLanguages ():void {
    if (_builtInLanguagesRegistered) { return }
    _builtInLanguagesRegistered = true

    Object.keys(_builtInLanguages).forEach((Language:string) => {
      const [ Module,Factory,Options ] = _builtInLanguages[Language]
      registerCodeEditorLanguage(Language, async () => (
        (await loadedLibrary(Module))[Factory](
          ...(Options == null ? [] : [ Options ])
        )
      ))
    })
  }


/**** DocOffsetIn - converts a 1-based line/column pair into a doc offset ****/

  function DocOffsetIn (Doc:any, Line:number, Column:number):number {
    const safeLine   = Math.max(1,Math.min(Math.round(Line),Doc.lines))
    const LineInfo   = Doc.line(safeLine)
    const safeColumn = Math.max(1,Math.min(Math.round(Column),LineInfo.length+1))
    return LineInfo.from + safeColumn-1
  }

/**** DiagnosticsFor - maps "JCL_CodeEditorError"s onto CM diagnostics ****/

  function DiagnosticsFor (Doc:any, ErrorList:JCL_CodeEditorError[]):any[] {
    return ErrorList.map((ErrorEntry:JCL_CodeEditorError) => {
      const { Line, Column, EndLine, EndColumn, Message, Severity } = ErrorEntry

      const from = DocOffsetIn(Doc, Line ?? 1, Column ?? 1)
      const to   = ((EndLine == null) && (EndColumn == null))
        ? Doc.line(Math.max(1,Math.min(Math.round(Line ?? 1),Doc.lines))).to
        : DocOffsetIn(Doc, EndLine ?? Line ?? 1, EndColumn ?? (Column ?? 1)+1)

      return {
        from, to:Math.max(from,to),
        severity:(
          [ 'error','warning','info' ].includes(Severity as string)
          ? Severity : 'error'
        ),
        message:String(Message ?? '(no message)')
      }
    })
  }



  export function legacyCodeEditor (PropSet:Indexable):any {
    return safelyRendered(() => {
      ensureCodeeditorStyles()

      const LibrariesAreReady = useLibraries(loadCodeEditorLibraries)

      PropSet = parseablePropSet(PropSet)
        const Classes          = acceptableTextline(PropSet.Class) ?? ''
        let   Value            = acceptableText    (PropSet.Value)
        const Language         = (acceptableTextline(PropSet.Language) ?? '').toLowerCase()
        const readonly         = acceptableBoolean (PropSet.readonly) ?? false
        const disabled         = acceptableBoolean (PropSet.disabled) ?? false
        const TabSize          = acceptableCardinal(PropSet.TabSize)  ?? 2
        const withLineNumbers  = acceptableBoolean (PropSet.withLineNumbers)  ?? true
        const withLineWrapping = acceptableBoolean (PropSet.withLineWrapping) ?? false
        const withSyntaxCheck  = acceptableBoolean (PropSet.withSyntaxCheck)  ?? false
        const Errors           = acceptableValue   (PropSet.Errors, (Value:any) => ValueIsListSatisfying(Value,ValueIsPlainObject)) ?? []
        const Linter           = acceptableFunction(PropSet.Linter)
        const LintDelay        = acceptableCardinal(PropSet.LintDelay) ?? 750
        const onValueChange     = acceptableFunction(PropSet.onValueChange)
        const onSelectionChange = acceptableFunction(PropSet.onSelectionChange)
        const onMount           = acceptableFunction(PropSet.onMount)
        const onUnmount         = acceptableFunction(PropSet.onUnmount)

      const ContainerRef = useRef<any>(null)
      const ViewRef      = useRef<any>(undefined)

    /**** keep callbacks up-to-date for the (once installed) editor view ****/

      const CallbackRef = useRef<Indexable>({})
        CallbackRef.current = { onValueChange, onSelectionChange, onUnmount, Linter }

    /**** allow setting "Value" externally and changing it internally ****/

      const externalValue = useRef(Value ?? '')
      const internalValue = useRef(Value ?? '')

      if ((Value != null) && (Value !== externalValue.current)) {
        externalValue.current = Value
        internalValue.current = Value
      }

    /**** "Compartments" allow for dynamic reconfiguration ****/

    // n.b.: the compartments can only be created once CodeMirror is available
    // - which is why that happens in the mounting effect below

      const CompartmentsRef = useRef<Indexable|undefined>(undefined)

    /**** mounting and unmounting (as soon as libraries are available) ****/

      useEffect(() => {
        if (! LibrariesAreReady) { return }    // still waiting for CodeMirror

        if (CompartmentsRef.current == null) {
          CompartmentsRef.current = {
            Language:new Compartment(),    Readability:new Compartment(),
            Indentation:new Compartment(), LineNumbers:new Compartment(),
            Wrapping:new Compartment(),    Linting:new Compartment()
          }
        }

        const Compartments = CompartmentsRef.current
        const View = new EditorView({
          parent:ContainerRef.current,
          state:EditorState.create({
            doc:internalValue.current,
            extensions:[
              highlightSpecialChars(), drawSelection(), ChangeHistory(),
              syntaxHighlighting(defaultHighlightStyle, { fallback:true }),
              lintGutter(),
              keymap.of([ ...defaultKeymap, ...historyKeymap, indentWithTab ]),
              Compartments.LineNumbers.of([]), Compartments.Language.of([]),
              Compartments.Readability.of([]), Compartments.Indentation.of([]),
              Compartments.Wrapping.of([]),    Compartments.Linting.of([]),
              EditorView.updateListener.of((Update:any) => {
                if (Update.docChanged) {
                  const newValue = Update.state.doc.toString()
                  internalValue.current = newValue
                  executeCallback(
                    'CodeEditor callback "onValueChange"',
                    CallbackRef.current.onValueChange, newValue
                  )
                }
                if (Update.selectionSet) {
                  const { from,to } = Update.state.selection.main
                  executeCallback(
                    'CodeEditor callback "onSelectionChange"',
                    CallbackRef.current.onSelectionChange, from,to
                  )
                }
              })
            ]
          })
        })
        ViewRef.current = View

      /**** provide an API handle for external editor controls ****/

        const Handle = {
          View,                                  // grants access to full CM API
          focus:   () => View.focus(),
          getValue:() => View.state.doc.toString(),
          setValue:(newValue:string):void => {
            expectText('editor value',newValue)
            View.dispatch({
              changes:{ from:0, to:View.state.doc.length, insert:newValue }
            })
          },
          getSelection:() => {
            const { from,to } = View.state.selection.main
            return { from, to, Text:View.state.sliceDoc(from,to) }
          },
          setSelection:(from:number, to:number = from):void => {
            const DocLength = View.state.doc.length
            const Anchor    = Math.max(0,Math.min(from,DocLength))
            const Head      = Math.max(Anchor,Math.min(to,DocLength))
            View.dispatch({
              selection:{ anchor:Anchor, head:Head }, scrollIntoView:true
            })
          },
          replaceSelection:(Text:string):void => {
            expectText('replacement',Text)
            View.dispatch(View.state.replaceSelection(Text))
          },
          undo:() => undoChange(View),
          redo:() => redoChange(View)
        }
        executeCallback('CodeEditor callback "onMount"', onMount, Handle)

        return () => {
          executeCallback(
            'CodeEditor callback "onUnmount"', CallbackRef.current.onUnmount
          )
          ViewRef.current = undefined
          View.destroy()
        }
      }, [ LibrariesAreReady ])


    /**** push externally changed "Value"s into the editor ****/

      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        const visibleValue = View.state.doc.toString()
        if (internalValue.current !== visibleValue) {
          View.dispatch({
            changes:{ from:0, to:visibleValue.length, insert:internalValue.current }
          })
        }
      })


    /**** dynamically reconfigure language support ****/

    // "LibrariesAreReady" is among the dependencies of all following effects
    // to make them run (again) right after the (asynchronously delayed)
    // editor installation
    // n.b.: "CompartmentsRef" is guaranteed to be set once "ViewRef" is (both
    // happen during mounting) - hence the non-null assertions ("!") below

      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        const { Language:LanguageCompartment } = CompartmentsRef.current!
        if ((Language === '') || (Language === 'text')) {
          View.dispatch({ effects:LanguageCompartment.reconfigure([]) })
          return
        }

        _ensureBuiltInLanguages()

        const Loader = CodeEditorLanguageRegistry[Language]
        if (Loader == null) {
          console.warn('CodeEditor: unsupported language ' + quoted(Language))
          View.dispatch({ effects:LanguageCompartment.reconfigure([]) })
          return
        }

        let LoadingWasCancelled = false
        Loader().then((LanguageSupport:any) => {
          if (LoadingWasCancelled || (ViewRef.current !== View)) { return }
          View.dispatch({
            effects:LanguageCompartment.reconfigure(LanguageSupport)
          })
        }).catch((Signal:any) => console.error(
          'CodeEditor: could not load support for language ' + quoted(Language),
          Signal
        ))
        return () => { LoadingWasCancelled = true }
      }, [ LibrariesAreReady, Language ])

    /**** dynamically reconfigure "readonly" and "disabled" ****/

      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        View.dispatch({
          effects:CompartmentsRef.current!.Readability.reconfigure([
            EditorState.readOnly.of(readonly || disabled),
            EditorView.editable.of(! disabled)
          ])
        })
      }, [ LibrariesAreReady, readonly,disabled ])

    /**** dynamically reconfigure indentation ****/

      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        const Indentation = Math.max(1,TabSize)
        View.dispatch({
          effects:CompartmentsRef.current!.Indentation.reconfigure([
            EditorState.tabSize.of(Indentation),
            indentUnit.of(' '.repeat(Indentation))
          ])
        })
      }, [ LibrariesAreReady, TabSize ])

    /**** dynamically reconfigure line numbers and line wrapping ****/

      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        const Compartments = CompartmentsRef.current!
        View.dispatch({ effects:[
          Compartments.LineNumbers.reconfigure(
            withLineNumbers ? lineNumbers() : []
          ),
          Compartments.Wrapping.reconfigure(
            withLineWrapping ? EditorView.lineWrapping : []
          )
        ] })
      }, [ LibrariesAreReady, withLineNumbers,withLineWrapping ])


    /**** display externally provided (syntax) errors ****/

    // note: while integrated linting is active (i.e., a "Linter" is set or
    // "withSyntaxCheck" was requested), externally provided "Errors" are
    // ignored

      useEffect(() => {
        const View = ViewRef.current
        if ((View == null) || (Linter != null) || withSyntaxCheck) { return }

        View.dispatch(
          setDiagnostics(View.state, DiagnosticsFor(View.state.doc,Errors))
        )
      }, [ LibrariesAreReady, JSON.stringify(Errors), (Linter != null), withSyntaxCheck ])


    /**** integrated linting (using CodeMirror's own scheduling) ****/

    // a custom "Linter" takes precedence over the built-in Lezer-based
    // syntax check requested with "withSyntaxCheck"

      const hasLinter = (Linter != null)
      useEffect(() => {
        const View = ViewRef.current
        if (View == null) { return }

        const { Linting } = CompartmentsRef.current!      // set while mounting

      /**** CustomLintSource - runs the given "Linter" ****/

        const CustomLintSource = async (lintedView:any) => {
          try {
            const ErrorList = await CallbackRef.current.Linter(
              lintedView.state.doc.toString()
            )
            return DiagnosticsFor(lintedView.state.doc, ErrorList ?? [])
          } catch (Signal) {
            console.error('CodeEditor: linting failed with', Signal)
            return []
          }
        }

      /**** LezerLintSource - collects error nodes from the syntax tree ****/

        const LezerLintSource = (lintedView:any) => {
          const DocLength = lintedView.state.doc.length
          const Tree = ensureSyntaxTree(lintedView.state,DocLength,500)
                       ?? syntaxTree(lintedView.state)

          const Diagnostics:any[] = []
          Tree.iterate({
            enter:(Node:any) => {
              if (Node.type.isError) {
                const from = Math.min(Node.from, Math.max(0,DocLength-1))
                const to   = Math.min(Math.max(Node.to,Node.from+1), DocLength)
                Diagnostics.push({
                  from, to:Math.max(from,to),
                  severity:'error', message:'syntax error'
                })
              }
            }
          })
          return Diagnostics
        }

      /**** now activate (or deactivate) the applicable lint source ****/

        switch (true) {
          case hasLinter:
            View.dispatch({ effects:Linting.reconfigure(
              linter(CustomLintSource, { delay:LintDelay })
            ) })
            break
          case withSyntaxCheck:
            View.dispatch({ effects:Linting.reconfigure(
              linter(LezerLintSource, { delay:LintDelay })
            ) })
            break
          default:
            View.dispatch({ effects:Linting.reconfigure([]) })
        }
      }, [ LibrariesAreReady, hasLinter, withSyntaxCheck, LintDelay ])



    /**** actual rendering ****/

      return html`<div
        class="jcl-component codeeditor ${disabled ? 'disabled' : ''} ${Classes}"
        ...${PropSet.RestProps} ref=${ContainerRef}
      />`
    })
  }

  const ensureCodeeditorStyles = /*@__PURE__*/ StylesheetInstallerFor('jcl-component.codeeditor',`
    .jcl-component.codeeditor {
      display:flex !important; flex-flow:column nowrap !important;
        align-items:stretch !important;
      position:relative; overflow:hidden;
      border:solid 1px #888888; border-radius:2px;
      background:white; color:black;
      font-size:14px;
    }

    .jcl-component.codeeditor > .cm-editor {
      flex:1 1 auto; overflow:hidden;
      width:100%; height:100%;
    }
    .jcl-component.codeeditor > .cm-editor.cm-focused {
      outline:solid 2px #6366f1; outline-offset:-2px;
    }

    .jcl-component.codeeditor.disabled {
      opacity:0.6; pointer-events:none;
    }

    @media (prefers-contrast: more) {
      .jcl-component.codeeditor > .cm-editor.cm-focused { outline:solid 3px currentColor }
    }
  `)

