        StrokeColor:'stroke',         StrokeWidth:'stroke-width',
        StrokeDashes:'stroke-dasharray',
        FillColor:'fill',             Opacity:'opacity',
        FontFamily:'font-family',     FontSize:'font-size',
        FontWeight:'font-weight',     FontStyle:'font-style'
