        const onTextRequest     = acceptableFunction(PropSet.onTextRequest)
        const onMount           = acceptableFunction(PropSet.onMount)
        const onUnmount         = acceptableFunction(PropSet.onUnmount)

      const ContainerRef = useRef<any>(null)
      const EditorRef    = useRef<any>(undefined)

