    /**** dynamic reconfiguration ****/

      useEffect(() => {
        const Editor = EditorRef.current
        if (Editor == null) { return }

        Editor.readonly = readonly
        if (readonly) {
          Editor.cancelPolyline()
          Editor.DragState = undefined
        }
      }, [readonly])

      useEffect(() => {
        const Editor = EditorRef.current
        if (Editor == null) { return }

        Editor.Size = { Width, Height }
        Editor.setViewBox({ x:0, y:0, Width, Height })
      }, [Width,Height])

      useEffect(() => {
        const Editor = EditorRef.current
        if (Editor == null) { return }

        Editor.GridSize   = GridSize
        Editor.snapToGrid = snapToGrid
        Editor.showsGrid  = showsGrid
        Editor.refreshGrid()
      }, [GridSize,snapToGrid,showsGrid])

    /**** value synchronisation ****/

