//------------------------------------------------------------------------------
//--                                NoteBoard                                 --
//------------------------------------------------------------------------------
//
// a board for freely placeable, movable and resizable "sticky notes". just
// like "legacyKanbanBoard" or "legacyNestedListView", this component is fully
// "controlled": both "Notes" (with position, size, content etc.) and
// "selectedKeys" are kept outside, the board itself only holds transient
// drag/resize state. capabilities follow callback presence (as in
// "legacyFlatListView"): notes may only be moved/resized with a given
// "onNotesChange" and only be selected with a given "onSelectionChange"
//
// while a note is being dragged or resized, its geometry follows the current
// gesture and external changes are ignored (see "nativeTextInput" for the
// same principle) - "onNotesChange" is nevertheless fired continuously
// (albeit rAF-throttled) with a single batch update for all selected notes.
// the stacking order of notes strictly follows their order within "Notes" -
// moving or selecting a note does *not* bring it to the front
//
// dragging a note into the "SensorWidth" wide sensor zone along the edges of
// the board pans the visible pane area, with a speed growing linearly with
// the penetration depth, up to "maxPanningSpeed" px/s

  export type JCL_StickyNoteKey      = string
  export type JCL_StickyNotePosition = { x:number, y:number }
  export type JCL_StickyNoteSize     = { Width:number, Height:number }

  export type JCL_StickyNote = {
    Key:      JCL_StickyNoteKey,
    Position: JCL_StickyNotePosition,   // in NotePane *content* coordinates
    Size:     JCL_StickyNoteSize,
    Type:     'text'|'html'|'markdown'|string,  // extensible via "NoteRenderer"
    Content:  string,
    FontFamily?:string, FontSize?:number, FontWeight?:number|string,
    LineHeight?:number,
    ForegroundColor?:string, BackgroundColor?:string
  }             // n.b.: no "zIndex" - stacking strictly follows "Notes" order

  export type JCL_KeyOfStickyNote    = (Note:Indexable) => JCL_StickyNoteKey
  export type JCL_StickyNoteRenderer = (Note:Indexable, isSelected:boolean) => any
  export type JCL_onStickyNoteSelectionChange = (newSelectedKeys:JCL_StickyNoteKey[]) => void
  export type JCL_onStickyNotesChange         = (changedNotes:Indexable[]) => void
  export type JCL_onStickyNoteContentChange   = (Key:JCL_StickyNoteKey, Content:string) => void

  const minStickyNoteWidth  = 80      // keeps titlebar and resize handle usable
  const minStickyNoteHeight = 50

/**** Default_KeyOfNote ****/

  function Default_KeyOfNote (Note:Indexable):JCL_StickyNoteKey {
    return ''+Note.Key
  }

/**** StickyNoteStyleFrom - inline CSS for resolved font and colour settings ****/

  function StickyNoteStyleFrom (Settings:Indexable):string {
    let Style = ''
      if (Settings.FontFamily      != null) { Style += `font-family:${Settings.FontFamily}; ` }
      if (Settings.FontSize        != null) { Style += `font-size:${Settings.FontSize}px; ` }
      if (Settings.FontWeight      != null) { Style += `font-weight:${Settings.FontWeight}; ` }
      if (Settings.LineHeight      != null) { Style += `line-height:${Settings.LineHeight}; ` }
      if (Settings.ForegroundColor != null) { Style += `color:${Settings.ForegroundColor}; ` }
      if (Settings.BackgroundColor != null) { Style += `background-color:${Settings.BackgroundColor}; ` }
    return Style
  }

/**** TabKeyHandler - inserts a real tab instead of moving the focus away ****/

// without this handler, pressing "Tab" inside a sticky note (or the Markdown
// editor dialog) would just move the focus to the next focusable element.
// Shift+Tab deliberately remains untouched and still moves the focus backwards

  function TabKeyHandler (Event:KeyboardEvent):void {
    if (
      (Event.key !== 'Tab') ||
      Event.shiftKey || Event.ctrlKey || Event.metaKey || Event.altKey
    ) { return }

    const TextArea = Event.target as HTMLTextAreaElement
    if (! (TextArea instanceof HTMLTextAreaElement)) { return }
    if (TextArea.readOnly || TextArea.disabled)      { return }

    Event.preventDefault()               // keeps the focus where it is

    let inserted:boolean = false
    try {                       // "execCommand" preserves the undo history...
      inserted = document.execCommand('insertText',false,'\t')
    } catch (Signal) { /* nop - "inserted" remains false */ }

    if (! inserted) {                       // ...the fallback does not
      const { selectionStart,selectionEnd, value } = TextArea
        TextArea.value = value.slice(0,selectionStart) + '\t' + value.slice(selectionEnd)
        TextArea.selectionStart = TextArea.selectionEnd = selectionStart+1
      TextArea.dispatchEvent(new InputEvent('input',{ bubbles:true }))
        // (n.b.: "Event" is shadowed by this handler's parameter)
    }
  }

/**** Default_NoteRendererFor - switches on "Note.Type", resolves fallbacks ****/

// "stickyNote" default settings are pure fallbacks: they only apply when the
// note in question does not set the given field itself (just like
// "Placeholder" or "disabled" in "nativeTextInput")

  function Default_NoteRendererFor (
    KeyOfNote:JCL_KeyOfStickyNote, Defaults:Indexable,
    onNoteContentChange?:Function
  ):JCL_StickyNoteRenderer {
    return (Note:Indexable, isSelected:boolean):any => {
      const ContentPropSet = {
        Content:Note.Content ?? '',
        onContentChange:(onNoteContentChange == null ? undefined : (
          (newContent:string) => executeCallback(
            'NoteBoard callback "onNoteContentChange"',
            onNoteContentChange, KeyOfNote(Note),newContent
          )
        )),
        FontFamily:     Note.FontFamily      ?? Defaults.FontFamily,
        FontSize:       Note.FontSize        ?? Defaults.FontSize,
        FontWeight:     Note.FontWeight      ?? Defaults.FontWeight,
        LineHeight:     Note.LineHeight      ?? Defaults.LineHeight,
        ForegroundColor:Note.ForegroundColor ?? Defaults.ForegroundColor,
        BackgroundColor:Note.BackgroundColor ?? Defaults.BackgroundColor,
      }

      switch (Note.Type) {
        case 'html':     return html`<${stickyHTMLNote}     ...${ContentPropSet}/>`
        case 'markdown': return html`<${stickyMarkdownNote} ...${ContentPropSet}/>`
        default:         return html`<${stickyTextNote}     ...${ContentPropSet}/>`
      }
    }
  }

  export function legacyNoteBoard (PropSet:Indexable):any {
    return safelyRendered(() => {
      ensureNoteboardStyles()

      PropSet = parseablePropSet(PropSet)
        const Classes                = acceptableTextline(PropSet.Class) ?? ''
        const Notes                  = acceptableValue   (PropSet.Notes, (Value:any) => ValueIsListSatisfying(Value,ValueIsPlainObject)) ?? missingProperty('Notes')
        const KeyOfNote              = acceptableFunction(PropSet.KeyOfNote) ?? Default_KeyOfNote
        const PaneWidth              = acceptableOrdinal (PropSet.PaneWidth)
        const PaneHeight             = acceptableOrdinal (PropSet.PaneHeight)
        const DefaultFontFamily      = acceptableTextline(PropSet.DefaultFontFamily)
        const DefaultFontSize        = acceptableNumber  (PropSet.DefaultFontSize)
        const DefaultFontWeight      = acceptableValue   (PropSet.DefaultFontWeight, (Value:any) => ValueIsNumber(Value) || ValueIsTextline(Value))
        const DefaultLineHeight      = acceptableNumber  (PropSet.DefaultLineHeight)
        const DefaultForegroundColor = acceptableTextline(PropSet.DefaultForegroundColor)
        const DefaultBackgroundColor = acceptableTextline(PropSet.DefaultBackgroundColor)
        let   selectedKeys           = acceptableValue   (PropSet.selectedKeys, (Value:any) => ValueIsListSatisfying(Value,ValueIsString)) ?? []
        const onSelectionChange      = acceptableFunction(PropSet.onSelectionChange)
        const onNotesChange          = acceptableFunction(PropSet.onNotesChange)
        const onNoteContentChange    = acceptableFunction(PropSet.onNoteContentChange)
        const SensorWidth            = acceptableOrdinal (PropSet.SensorWidth)     ?? 20
        const maxPanningSpeed        = acceptableOrdinal (PropSet.maxPanningSpeed) ?? 400

      const BoardIsSelectable = (onSelectionChange != null)     // capability...
      const BoardIsDraggable  = (onNotesChange != null)    // ...follows callback

      const Defaults = {
        FontFamily:DefaultFontFamily, FontSize:DefaultFontSize,
        FontWeight:DefaultFontWeight, LineHeight:DefaultLineHeight,
        ForegroundColor:DefaultForegroundColor,
        BackgroundColor:DefaultBackgroundColor,
      }
      const NoteRenderer = acceptableFunction(PropSet.NoteRenderer) ??
        Default_NoteRendererFor(KeyOfNote as JCL_KeyOfStickyNote,Defaults,onNoteContentChange)

    /**** validate "Notes" (reject notes with identical keys) ****/

    // "validatedKeySetFrom" is a module-level helper (see "auxiliary
    // functions") which is shared with "legacyDataFlowProcessView"

      const NoteKeyList:JCL_StickyNoteKey[] = Notes.map((Note:Indexable) => String(
        executedCallback('NoteBoard callback "KeyOfNote"', KeyOfNote, Note)
      ))
      const NoteKeySet = validatedKeySetFrom(NoteKeyList,'"Notes"')

    /**** sanitize "selectedKeys" (ignore unknown keys and double entries) ****/

    // "sanitizedSelection" is a module-level helper (see "auxiliary
    // functions") which is shared with "legacyDataFlowProcessView"

      const SelectionSet:Set<JCL_StickyNoteKey> = new Set()
      if (BoardIsSelectable) {
        selectedKeys = sanitizedSelection(selectedKeys,NoteKeySet)
        selectedKeys.forEach((Key:JCL_StickyNoteKey) => SelectionSet.add(Key))
      }

    /**** changeStickyNoteSelection ****/

    // a relative of NestedListView's "changeSelection" - but here, "additively"
    // is meant to be "Event.shiftKey || Event.metaKey || Event.ctrlKey"

      function changeStickyNoteSelection (
        Key:JCL_StickyNoteKey, additively:boolean
      ):JCL_StickyNoteKey[] {
        let newSelection:JCL_StickyNoteKey[]
          if (additively) {
            newSelection = (
              SelectionSet.has(Key)                             // deselect note
              ? selectedKeys.filter(
                  (selectedKey:JCL_StickyNoteKey) => selectedKey !== Key
                )
              : [ ...selectedKeys,Key ]                           // select note
            )
          } else {                                           // select note only
            newSelection = [Key]
          }
        executeCallback(
          'NoteBoard callback "onSelectionChange"',
          onSelectionChange, newSelection
        )                         // caller should update selection and rerender

        return newSelection
      }

    /**** transient gesture state - the *only* internal NoteBoard state ****/

      const ScrollerRef = useRef<any>(null)     // the scrolling NoteBoard itself
      const GestureRef  = useRef<Indexable|undefined>(undefined)
      const rerender    = useRerenderer()

      useEffect(() => {                  // clean up when unmounted mid-gesture
        return () => {
          const Gesture = GestureRef.current
          if (Gesture != null) {
            if (Gesture.ChangeRAF  != null) { cancelAnimationFrame(Gesture.ChangeRAF) }
            if (Gesture.PanningRAF != null) { cancelAnimationFrame(Gesture.PanningRAF) }
            GestureRef.current = undefined
          }
        }
      },[])

    /**** GeometryFromGesture - applies the gesture delta, clamped to the pane ****/

    // "clamped" is a module-level helper (see "auxiliary functions")

      function GeometryFromGesture (StartGeometry:Indexable):Indexable {
        const { Mode, dx,dy } = GestureRef.current as Indexable
        const { x,y, Width,Height } = StartGeometry

        if (Mode === 'move') {
          return {
            x:clamped(x+dx, 0,actualPaneWidth-Width),
            y:clamped(y+dy, 0,actualPaneHeight-Height),
            Width,Height
          }
        } else {                              // 'resize' - "se" handle only, as
          return {                           // in "DialogView"s resizing logic
            x,y,
            Width: clamped(Width+dx,  minStickyNoteWidth, actualPaneWidth-x),
            Height:clamped(Height+dy, minStickyNoteHeight,actualPaneHeight-y)
          }
        }
      }

    /**** displayedGeometryOf ****/

    // while a note takes part in a gesture, its externally given geometry is
    // ignored and the gesture-driven one shown instead - the very same
    // "ignore external changes while this control is in use" principle as in
    // "nativeTextInput". after the gesture, notes are purely prop-driven again

      function displayedGeometryOf (
        Note:Indexable, Key:JCL_StickyNoteKey
      ):Indexable {
        const StartGeometry = GestureRef.current?.StartGeometryByKey[Key]
        return (
          StartGeometry == null
          ? { x:Note.Position.x, y:Note.Position.y,
              Width:Note.Size.Width, Height:Note.Size.Height }
          : GeometryFromGesture(StartGeometry)
        )
      }

    /**** changedNotesFromGesture - a single batch update per gesture step ****/

      function changedNotesFromGesture ():Indexable[] {
        const Gesture = GestureRef.current
        if (Gesture == null) { return [] }

        const changedNotes:Indexable[] = []
        Notes.forEach((Note:Indexable, Index:number) => {
          const StartGeometry = Gesture.StartGeometryByKey[NoteKeyList[Index]]
          if (StartGeometry != null) {
            const { x,y, Width,Height } = GeometryFromGesture(StartGeometry)
            changedNotes.push({ ...Note, Position:{ x,y }, Size:{ Width,Height } })
          }
        })
        return changedNotes
      }

    /**** deferredNotesChange - keeps "onNotesChange" rAF-throttled ****/

    // the caller thus receives *every* change (not just the final result) but
    // need not mirror the new values back synchronously - the gesture-driven
    // geometry (see "displayedGeometryOf") cushions any latency

      function deferredNotesChange ():void {
        const Gesture = GestureRef.current
        if ((Gesture == null) || (Gesture.ChangeRAF != null)) { return }

        Gesture.ChangeRAF = requestAnimationFrame(() => {
          const Gesture = GestureRef.current
          if (Gesture == null) { return }

          Gesture.ChangeRAF = undefined
          const changedNotes = changedNotesFromGesture()
          if (changedNotes.length > 0) {
            executeCallback(
              'NoteBoard callback "onNotesChange"', onNotesChange, changedNotes
            )
          }
        })
      }

    /**** startedGesture - selects the dragged note first, "if not done yet" ****/

      function startedGesture (
        Mode:'move'|'resize', NoteKey:JCL_StickyNoteKey, Event:PointerEvent|null
      ):void {
        let GestureKeys:JCL_StickyNoteKey[] = [NoteKey]
        if (BoardIsSelectable) {
          let selection = selectedKeys
          if (! SelectionSet.has(NoteKey)) {
            const additively = isAdditive(Event)
            selection = changeStickyNoteSelection(NoteKey,additively)
          }
          if (selection.includes(NoteKey)) { GestureKeys = selection }
        }           // a selected note is moved/resized together with all other
                    // selected notes - by the same dx/dy

        const StartGeometryByKey:Indexable = {}
        Notes.forEach((Note:Indexable, Index:number) => {
          if (GestureKeys.includes(NoteKeyList[Index])) {
            StartGeometryByKey[NoteKeyList[Index]] = {
              x:Note.Position.x, y:Note.Position.y,
              Width:Note.Size.Width, Height:Note.Size.Height
            }
          }
        })

        GestureRef.current = {
          Mode, StartGeometryByKey, dx:0,dy:0,
          lastClientX:undefined, lastClientY:undefined,
          ChangeRAF:undefined, PanningRAF:undefined, PanningTimestamp:undefined
        }
        rerender()
      }

    /**** continuedGesture ****/

      function continuedGesture (
        dx:number,dy:number, Event:PointerEvent|null
      ):void {
        const Gesture = GestureRef.current
        if (Gesture == null) { return }

        Gesture.dx = dx; Gesture.dy = dy
        if (Event != null) {
          Gesture.lastClientX = Event.clientX; Gesture.lastClientY = Event.clientY
        }

        if ((Gesture.Mode === 'move') && (Gesture.PanningRAF == null)) {
          Gesture.PanningTimestamp = undefined
          Gesture.PanningRAF = requestAnimationFrame(
            (Timestamp:number) => PanningStepRef.current?.(Timestamp)
          )                 // the panning loop ends itself outside sensor zones
        }

        rerender()                 // live feedback w/o waiting for the caller...
        deferredNotesChange()         // ...who is informed (rAF-throttled) here
      }

    /**** finishedGesture ****/

      function finishedGesture (dx:number,dy:number):void {
        const Gesture = GestureRef.current
        if (Gesture == null) { return }

        Gesture.dx = dx; Gesture.dy = dy

        if (Gesture.ChangeRAF  != null) { cancelAnimationFrame(Gesture.ChangeRAF) }
        if (Gesture.PanningRAF != null) { cancelAnimationFrame(Gesture.PanningRAF) }

        const changedNotes = changedNotesFromGesture()
        GestureRef.current = undefined

        if (changedNotes.length > 0) {
          executeCallback(             // the final, non-throttled batch update
            'NoteBoard callback "onNotesChange"', onNotesChange, changedNotes
          )
        }
        rerender()            // from now on, notes are purely prop-driven again
      }

    /**** cancelledGesture - reverts all live updates sent so far ****/

      function cancelledGesture ():void {
        const Gesture = GestureRef.current
        if (Gesture == null) { return }

        if (Gesture.ChangeRAF  != null) { cancelAnimationFrame(Gesture.ChangeRAF) }
        if (Gesture.PanningRAF != null) { cancelAnimationFrame(Gesture.PanningRAF) }

        const revertedNotes:Indexable[] = []
        Notes.forEach((Note:Indexable, Index:number) => {
          const StartGeometry = Gesture.StartGeometryByKey[NoteKeyList[Index]]
          if (StartGeometry != null) {
            const { x,y, Width,Height } = StartGeometry
            revertedNotes.push({ ...Note, Position:{ x,y }, Size:{ Width,Height } })
          }
        })

        GestureRef.current = undefined

        if (revertedNotes.length > 0) {
          executeCallback(
            'NoteBoard callback "onNotesChange"', onNotesChange, revertedNotes
          )
        }
        rerender()
      }

    /**** PanningStep - pans while a dragged note remains in a sensor zone ****/

    // as "Position"s are kept in NotePane *content* coordinates, panning moves
    // the pointer (and, thus, the dragged notes) within the pane without any
    // further correction - the note simply stays under the pointer.
    // "PanningVelocity" and "clampedPanningInterval" are module-level helpers
    // (see "auxiliary functions") shared with "legacyDataFlowProcessView"

      function PanningStep (Timestamp:number):void {
        const Gesture  = GestureRef.current
        const Scroller = ScrollerRef.current
        if ((Gesture == null) || (Gesture.Mode !== 'move') || (Scroller == null)) {
          return
        }

        const { lastClientX,lastClientY } = Gesture
        if ((lastClientX == null) || (lastClientY == null)) {
          Gesture.PanningRAF = undefined; Gesture.PanningTimestamp = undefined
          return
        }

        const { vx,vy } = PanningVelocity(
          Scroller.getBoundingClientRect(), lastClientX,lastClientY,
          SensorWidth, maxPanningSpeed
        )

        if ((vx === 0) && (vy === 0)) {
          Gesture.PanningRAF = undefined; Gesture.PanningTimestamp = undefined
          return             // leaves the loop - "continuedGesture" restarts it
        }

        const dt = clampedPanningInterval(Gesture,Timestamp)

        const oldScrollLeft = Scroller.scrollLeft
        const oldScrollTop  = Scroller.scrollTop
          Scroller.scrollLeft = oldScrollLeft + vx*dt
          Scroller.scrollTop  = oldScrollTop  + vy*dt

        Gesture.dx += Scroller.scrollLeft-oldScrollLeft  // uses the *actual*...
        Gesture.dy += Scroller.scrollTop -oldScrollTop  // ...(clamped) deltas

        rerender()
        deferredNotesChangeRef.current?.()

        Gesture.PanningRAF = requestAnimationFrame(
          (Timestamp:number) => PanningStepRef.current?.(Timestamp)
        )
      }

    /**** refs keep the (long-running) panning loop out of stale closures ****/

      const PanningStepRef = useRef<Function>()
        PanningStepRef.current = PanningStep
      const deferredNotesChangeRef = useRef<Function>()
        deferredNotesChangeRef.current = deferredNotesChange

    /**** default pane size = current size of the NoteBoard itself ****/

      const measuredPaneSize = useMeasuredPaneSize(ScrollerRef)

      const actualPaneWidth  = PaneWidth  ?? measuredPaneSize.Width
      const actualPaneHeight = PaneHeight ?? measuredPaneSize.Height

    /**** resolvedStyleOf - note settings first, board defaults second ****/

      function resolvedStyleOf (Note:Indexable):string {
        return StickyNoteStyleFrom({
          FontFamily:     Note.FontFamily      ?? DefaultFontFamily,
          FontSize:       Note.FontSize        ?? DefaultFontSize,
          FontWeight:     Note.FontWeight      ?? DefaultFontWeight,
          LineHeight:     Note.LineHeight      ?? DefaultLineHeight,
          ForegroundColor:Note.ForegroundColor ?? DefaultForegroundColor,
          BackgroundColor:Note.BackgroundColor ?? DefaultBackgroundColor,
        })
      }

    /**** actual rendering ****/

      return html`<div
        class="jcl-component noteboard ${Classes}"
        ref=${ScrollerRef} ...${PropSet.RestProps}
      >
        <div class="notepane"
          style="width:${actualPaneWidth}px; height:${actualPaneHeight}px"
        >
          ${Notes.map((Note:Indexable, Index:number) => {
            const NoteKey    = NoteKeyList[Index]
            const isSelected = SelectionSet.has(NoteKey)

            return html`<${StickyNoteView} key=${NoteKey}
              NoteKey=${NoteKey} Geometry=${displayedGeometryOf(Note,NoteKey)}
              isSelected=${isSelected} isSelectable=${BoardIsSelectable}
              isDraggable=${BoardIsDraggable} NoteStyle=${resolvedStyleOf(Note)}
              ScrollerOf=${() => ScrollerRef.current}
              renderedContent=${executedCallback(
                'NoteBoard callback "NoteRenderer"', NoteRenderer, Note,isSelected
              )}
              onNoteClick=${(x:number,y:number, Event:PointerEvent) =>
                changeStickyNoteSelection(
                  NoteKey, isAdditive(Event)
                )
              }
              onMoveStart=${(dx:number,dy:number, x:number,y:number, Event:PointerEvent) =>
                startedGesture('move',NoteKey,Event)
              }
              onMoveContinuation=${(dx:number,dy:number, x:number,y:number, Event:PointerEvent) =>
                continuedGesture(dx,dy,Event)
              }
              onMoveFinish=${(dx:number,dy:number) => finishedGesture(dx,dy)}
              onMoveCancellation=${() => cancelledGesture()}
              onResizeStart=${(dx:number,dy:number, x:number,y:number, Event:PointerEvent) =>
                startedGesture('resize',NoteKey,Event)
              }
              onResizeContinuation=${(dx:number,dy:number, x:number,y:number, Event:PointerEvent) =>
                continuedGesture(dx,dy,Event)
              }
              onResizeFinish=${(dx:number,dy:number) => finishedGesture(dx,dy)}
              onResizeCancellation=${() => cancelledGesture()}
            />`
          })}
        </>
      </>`
    })
  }

/**** StickyNoteView (for internal use only) ****/

// renders a single sticky note: a titlebar (for click-selection and dragging),
// a content area (filled by the "NoteRenderer") and - if permitted - a resize
// handle (a 24x24px bitmap) overlaid onto the lower right corner. clicks and
// drags are told apart by "useClickDragging" (with its default threshold of
// 4px), the resize handle uses a plain "useDragging" with "onlyFrom" (as in
// "DialogView"s "resizing" logic, but with the "se" handle only)

  function StickyNoteView (PropSet:Indexable):any {
    const {
      NoteKey, Geometry, isSelected, isSelectable, isDraggable,
      NoteStyle, ScrollerOf, renderedContent, onNoteClick,
      onMoveStart, onMoveContinuation, onMoveFinish, onMoveCancellation,
      onResizeStart, onResizeContinuation, onResizeFinish, onResizeCancellation
    } = PropSet

    const ViewRef = useRef<any>(null)

    const handleTitlebarPointerDown = useClickDragging({
      ViewRef, Container:ScrollerOf, onlyFrom:'.titlebar',
      onClick:            (isSelectable ? onNoteClick        : undefined),
      onDragStart:        (isDraggable  ? onMoveStart        : undefined),
      onDragContinuation: (isDraggable  ? onMoveContinuation : undefined),
      onDragFinish:       (isDraggable  ? onMoveFinish       : undefined),
      onDragCancellation: (isDraggable  ? onMoveCancellation : undefined),
    })

    const handleResizePointerDown = useDragging({
      ViewRef, Container:ScrollerOf, onlyFrom:'.resize-handle',
      onDragStart:        (isDraggable ? onResizeStart        : undefined),
      onDragContinuation: (isDraggable ? onResizeContinuation : undefined),
      onDragFinish:       (isDraggable ? onResizeFinish       : undefined),
      onDragCancellation: (isDraggable ? onResizeCancellation : undefined),
    })

    return html`<div
      class="stickynote${isSelected ? ' selected' : ''}"
      style="left:${Geometry.x}px; top:${Geometry.y}px; width:${Geometry.Width}px; height:${Geometry.Height}px; ${NoteStyle}"
      ref=${ViewRef} data-note-key=${NoteKey}
      onPointerDown=${(Event:PointerEvent) => {
        handleResizePointerDown?.(Event)     // "onlyFrom" tells these two apart
        handleTitlebarPointerDown?.(Event)
      }}
    >
      <div class="titlebar"/>
      <div class="content-area">${renderedContent}</>
      ${isDraggable && html`<div class="resize-handle" aria-hidden="true"/>`}
    </>`
  }

