//
// content view for sticky notes of type "text" - it has no public API of its
// own but is only ever rendered by a NoteBoard's default "NoteRenderer".
// by default, contents are autowrapped - as soon as "Content" contains a tab
// character, however, autowrapping is switched off and tabs are rendered
// "TabWidth" pixels wide (a setting "nativeTextInput" itself does not offer).
// pressing "Tab" inserts a real tab character (see "TabKeyHandler") rather
// than moving the focus to the next sticky note - which is also why "Content"
// is validated with "ValueIsTextWithTabs" rather than plain "ValueIsText"
//
// n.b.: exported (unlike before) so that other hosts (e.g. WAT) may use this
// content view outside of a "NoteBoard" as well - see "stickyTextNote" under
// "WebApp Tinkerer (WAT)|WAT Runtime|...|built-in Behaviours|other Controls"

  export function stickyTextNote (PropSet:Indexable):any {
    return safelyRendered(() => {
      PropSet = parseablePropSet(PropSet)
        const Content         = acceptableValue   (PropSet.Content,ValueIsTextWithTabs) ?? ''
        const onContentChange = acceptableFunction(PropSet.onContentChange)
        const TabWidth        = acceptableOrdinal (PropSet.TabWidth) ?? 10

      const LineWrapping = ! Content.includes('\t')  // tabs preclude wrapping

      return html`<${nativeTextInput}
        Class="sticky-note-content sticky-text-note"
        Style=${StickyNoteStyleFrom(PropSet) + (
          LineWrapping ? '' : `tab-size:${TabWidth}px;`
        )}
        Value=${Content} wrap=${LineWrapping}
        readonly=${onContentChange == null}
        onKeyDown=${TabKeyHandler}
        onValueInput=${(newContent:string) => executeCallback(
          'stickyTextNote callback "onContentChange"', onContentChange, newContent
        )}
      />`
    })
  }//------------------------------------------------------------------------------
