        const PointerAccuracyMQ     = window.matchMedia('(pointer: coarse)')
        const HoverCapabilityMQ     = window.matchMedia('(hover: hover)')
        const MotionEffectMQ        = window.matchMedia('(prefers-reduced-motion: reduce)')
        const ContrastEnhancementMQ = window.matchMedia('(prefers-contrast: more)')
        const ContrastReductionMQ   = window.matchMedia('(prefers-contrast: less)')

        ThemingMQ.addEventListener            ('change', handleTheme)
        PointerAccuracyMQ.addEventListener    ('change', handlePointerAccuracy)
        HoverCapabilityMQ.addEventListener    ('change', handleHoverCapability)
        MotionEffectMQ.addEventListener       ('change', handleMotionEffect)
        ContrastEnhancementMQ.addEventListener('change', handleContrast)
        ContrastReductionMQ.addEventListener  ('change', handleContrast)

