          ThemingMQ.removeEventListener            ('change', handleTheme)
          PointerAccuracyMQ.removeEventListener    ('change', handlePointerAccuracy)
          HoverCapabilityMQ.removeEventListener    ('change', handleHoverCapability)
          MotionEffectMQ.removeEventListener       ('change', handleMotionEffect)
