  export async function readFileAsText (File:globalThis.File):Promise<string> {
    return new Promise((resolve,reject) => {
      const Reader = new FileReader()
        Reader.onload  = () => resolve(Reader.result as string)
        Reader.onerror = () => reject(Reader.error ?? new Error('Loading failed'))
        Reader.onabort = () => reject(new Error('Loading was aborted'))
      Reader.readAsText(File)
    })
  }

