/**** MarkdownAsText ****/

  export async function MarkdownAsText (Markdown:string):Promise<string> {
    expectText('markdown document',Markdown)
    try {
      await loadMarkdownLibraries()

      let _ListDepth = 0            // tracks nesting depth for list indentation

      const MarkdownRenderer = new Marked()
      MarkdownRenderer.use({
        gfm:true, breaks:true,
        renderer: {
          heading (ArgSet:Indexable):string {
            return `\n${strippedHTML((this as any).parser.parseInline(ArgSet.tokens))}\n\n`
          },
          paragraph (ArgSet:Indexable):string {
            return `${strippedHTML((this as any).parser.parseInline(ArgSet.tokens))}\n\n`
          },
          list (ArgSet:Indexable):string {
            _ListDepth++
              let Body = ''
              for (const Item of ArgSet.items) { Body += this.listitem(Item) }
            _ListDepth--
            return Body + '\n'
          },
          listitem (ArgSet:Indexable):string {
            const Indentation = '  '.repeat(_ListDepth - 1)
            const hasBlock    = ArgSet.tokens.some((Token:any) => Token.type === 'list')
            const Body = hasBlock
              ? strippedHTML((this as any).parser.parse(ArgSet.tokens)).trim()
              : strippedHTML((this as any).parser.parseInline(ArgSet.tokens))
            return `${Indentation}- ${Body}\n`
          },
          link (ArgSet:Indexable):string {
            return strippedHTML((this as any).parser.parseInline(ArgSet.tokens))
          },
          image (ArgSet:Indexable):string {
            return `[${ArgSet.text}]`
          },
          code (ArgSet:Indexable):string {
            return `${ArgSet.text}\n\n`
          },
          blockquote (ArgSet:Indexable):string {
            return `${strippedHTML((this as any).parser.parse(ArgSet.tokens))}\n\n`
          },
          br ():string {
            return '\n'
          },
          html ():string {
            return ''
          },
          hr ():string {
            return '----\n\n'
          },
        }
      })
      MarkdownRenderer.use(markedKatex({ nonStandard:true }))

      return (await MarkdownRenderer.parse(Markdown)).replace(/^\s+|\s+$/g,'').replace(/\n{3,}/g,'\n\n')
    } catch (Signal:any) {
      throwError('ConversionError: could not convert the given Markdown into plain text, reason: ' + Signal)
    }
  }

/**** MarkdownFileReadAsHTML ****/

  export async function MarkdownFileReadAsHTML (File:globalThis.File):Promise<string> {
    const Markdown = await readFileAsText(File)
    return MarkdownAsHTML(Markdown)
  }

/**** MarkdownAsHTML ****/

  export async function MarkdownAsHTML (Markdown:string):Promise<string> {
    expectText('markdown document',Markdown)
    try {
      await loadMarkdownLibraries()

      const MarkdownRenderer = new Marked()
        MarkdownRenderer.use(markedHighlight({
          langPrefix: 'hljs language-',
          highlight (Code:string, Lang:string):string {
            const Language = hljs.getLanguage(Lang) ? Lang : 'plaintext'
            return hljs.highlight(Code,{ language:Language }).value
          }
        }))
        MarkdownRenderer.setOptions({
          gfm:true, breaks:true,
        })
      MarkdownRenderer.use(markedKatex({ nonStandard:true }))

      return await MarkdownRenderer.parse(Markdown)
    } catch (Signal:any) {
      throwError('ConversionError: could not convert the given Markdown into HTML, reason: ' + Signal)
    }
  }

/**** strippedHTML — removes HTML tags from a string ****/

  function strippedHTML (HTML:string):string {
    return HTML.replace(/<[^>]+>/g,'')
  }

