// "pdfjs-dist" is heavy and, thus, loaded lazily (and only once) upon first
// use in order to keep it out of the main bundle

  let _getPDFDocument:any
  async function loadedPDFjs ():Promise<any> {
    if (_getPDFDocument == null) {
      const { getDocument, GlobalWorkerOptions } = await import('pdfjs-dist')

      GlobalWorkerOptions.workerSrc = new URL(/* @vite-ignore */ './pdf.worker.min.mjs', import.meta.url).href
    // the Worker URL is relative to the delivering bundle directory: in the
    // bundled build, "import.meta.url" points to the main bundle;
    // "pdf.worker.min.mjs" is expected alongside it. In the unbundled dev
    // build (node_modules), the original path
    // "pdfjs-dist/build/pdf.worker.min.mjs" works via the Node resolver.
    // "@vite-ignore" suppresses the (intended) "doesn't exist at build time"
    // warning - the URL is deliberately resolved at runtime only.

      _getPDFDocument = getDocument
    }
    return _getPDFDocument
  }

/**** PDFFileReadAsText ****/

  export async function PDFFileReadAsText (File:globalThis.File):Promise<string> {
    const Buffer = await readFileAsBinary(File)
    return PDFasText(Buffer)
  }

/**** PDFasText ****/

  export async function PDFasText (Buffer:ArrayBuffer):Promise<string> {
    expectInstanceOf('PDF document',Buffer,ArrayBuffer,'binary buffer')
    try {
      const getDocument = await loadedPDFjs()
      const PDF = await getDocument({
        data:   Buffer,
        wasmUrl:new URL(/* @vite-ignore */ './vendors/', import.meta.url).href,
      }).promise

      let Text = ''
        for (let i = 1; i <= PDF.numPages; i++) {
          const Page    = await PDF.getPage(i)
          const Content = await Page.getTextContent()
          Text += (Content.items as Array<{ str:string, hasEOL:boolean }>)
            .map((Item) => Item.str + (Item.hasEOL ? '\n' : ' '))
            .join('').replace(/ +/g,' ') + '\n'
        }
      return Text
    } catch (Signal:any) {
      throwError('ConversionError: could not convert the given PDF file into plain text, reason: ' + Signal)
    }
  }

//----------------------------------------------------------------------------//
//                                 HTMLtoText                                 //
//----------------------------------------------------------------------------//

  type HTMLtoTextCallbacks = {
    processStartTag: (Tag:string, Attributes:HTMLAttribute[], isUnary:boolean, isTopLevel:boolean) => void,
    processEndTag:   (Tag:string) => void,
    processText:     (Text:string, isTopLevel:boolean) => void,
    processComment:  (Comment:string) => void,
    ignoredTag?: string,
    href?:       string,
  }

/**** HTMLtoText ****/

  export function HTMLtoText (HTMLContent:string):string {
    expectText('HTML document',HTMLContent)
    if (/^\s*<!DOCTYPE/i.test(HTMLContent)) {
      HTMLContent = HTMLContent.replace(/^\s*<!DOCTYPE[^>]*>/i,'').trim()
    }

    const TagIsToBeIgnored:Record<string,true> = {
      head:true, base:true, link:true, meta:true, noscript:true,
      script:true, style:true, title:true
    }

    let Result  = ''
    let ListStack:string[]    = []
    let ListCounters:number[] = []
    let inPre   = false, inCode     = false
    let inTable = false, inTableRow = false
    let lastTag = ''
    let justStarted = true

  /**** Callbacks for HTML Parser ****/

    const Callbacks:HTMLtoTextCallbacks = {
      processStartTag: function (Tag, Attributes, isUnary, isTopLevel) {
        if (TagIsToBeIgnored[Tag]) {
          Callbacks.ignoredTag = Tag
          return
        }
        if (Callbacks.ignoredTag != null) { return }

        switch (Tag) {
          case 'h1': case 'h2': case 'h3': case 'h4': case 'h5': case 'h6':
            if (! justStarted) { addNewline(Tag === 'h1' ? 3 : 2) }
            justStarted = false
            break
          case 'section': addNewline(); break
          case 'ul':      addNewline(); ListStack.push('-'); break
          case 'ol':      addNewline(); ListStack.push('1'); ListCounters.push(1); break
          case 'li':
            addNewline()
            Result += ListItemIndentation()
            switch (ListStack[ListStack.length-1]) {
              case '-': Result += '- '; break
              case '1': Result += (ListCounters[ListCounters.length-1]!++) + '. '; break
            }
            break
          case 'table': addNewline();                inTable    = true; break
          case 'tr':    addNewline(); Result += '|'; inTableRow = true; break
          case 'td': case 'th':
            if (! inTableRow) { Result += '|'; inTableRow = true }
            Result += ' '
            break
          case 'blockquote':          addNewline(); break
          case 'pre':  inPre  = true; addNewline(); break
          case 'code': inCode = true; break
          case 'br':   addNewline();  break
          case 'hr':   addNewline(2); Result += '----'; addNewline(2); break
          case 'a':
            Callbacks.href = (Attributes.find(
              (Attribute) => Attribute.Name === 'href'
            ) || {} as any).Value
            break
          case 'img':
            let Alt = (Attributes.find((Attribute) => Attribute.Name === 'alt') || {} as any).Value || ''
            let Src = (Attributes.find((Attribute) => Attribute.Name === 'src') || {} as any).Value || ''
            Result += ` (${Alt}) [${Src}] `
            break
        }

        lastTag = Tag
      },

      processEndTag: function (Tag) {
        if (Callbacks.ignoredTag != null) {
          if (Callbacks.ignoredTag === Tag) { delete Callbacks.ignoredTag }
          return
        }

        switch (Tag) {
          case 'h1': case 'h2': case 'h3': case 'h4': case 'h5': case 'h6':
            addNewline(2)
            break
          case 'ul':    ListStack.pop();                     addNewline(); break
          case 'ol':    ListStack.pop(); ListCounters.pop(); addNewline(); break
          case 'tr':    Result += '|'; inTableRow = false; break
          case 'td':
          case 'th':    Result += '|'; break
          case 'table': inTable = false; addNewline(); break
          case 'pre':   addNewline(); inPre  = false; break
          case 'code':  inCode = false; break
          case 'a':     if (Callbacks.href != null) {
                          Result += ` [${Callbacks.href}]`
                        }
                        delete Callbacks.href
        }
        lastTag = ''
      },

      processText: function (Text, isTopLevel) {
        if (Callbacks.ignoredTag != null) { return }

        if ((Text.trim() === '') && ! inPre && ! inCode) {
          return
        }

        addText(withDecodedHTMLEntities(Text))
        justStarted = false
      },

      processComment: function (Comment) {
        // ignore comments
      }
    }
    parseHTML(HTMLContent, Callbacks)

    return Result.replace(/^\s+|\s+$/g, '').replace(/\n{3,}/g, '\n\n')

  /**** addText ****/

    function addText (Text:string):void {
      if (inPre || inCode) {
        Result += Text
      } else {
        Result += Text.replace(/\s+/g, ' ')
      }
    }

  /**** addNewline ****/

    function addNewline (Count:number = 1):void {
      Result = Result.replace(inPre ? /\n*$/ : /\s*$/, '')
      Result += '\n'.repeat(Count)
    }

  /**** ListItemIndentation ****/

    function ListItemIndentation ():string {
      return '  '.repeat(ListStack.length)
    }

  /**** withDecodedHTMLEntities ****/

    function withDecodedHTMLEntities (Text:string):string {
      if (typeof document !== 'undefined') {
        const TextArea = document.createElement('textarea')
        TextArea.innerHTML = Text
        return TextArea.value
      } else {
        return Text
          .replace(/&amp;/g,  '&')
          .replace(/&lt;/g,   '<')
          .replace(/&gt;/g,   '>')
          .replace(/&quot;/g, '"')
          .replace(/&apos;/g, '\'')
          .replace(/&#(\d+);/g,     (_, n) => String.fromCodePoint(Number(n)))
          .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCodePoint(parseInt(h, 16)))
      }
    }
  }

//----------------------------------------------------------------------------//
//                               HTMLtoMarkdown                               //
//----------------------------------------------------------------------------//

  type HTMLtoMarkdownCallbacks = {
    processStartTag: (Tag:string, Attributes:HTMLAttribute[], isUnary:boolean, isTopLevel:boolean) => void,
    processEndTag:   (Tag:string) => void,
    processText:     (Text:string, isTopLevel:boolean) => void,
    processComment:  (Comment:string) => void,
    ignoredTag?: string,
    href?:       string,
  }

  export function HTMLtoMarkdown (HTMLContent:string):string {
    expectText('HTML document',HTMLContent)
    if (/^\s*<!DOCTYPE/i.test(HTMLContent)) {
      HTMLContent = HTMLContent.replace(/^\s*<!DOCTYPE[^>]*>/i,'').trim()
    }

    const TagIsToBeIgnored:Record<string,true> = {
      head:true, base:true, link:true, meta:true, noscript:true,
      script:true, style:true, title:true, svg:true, semantics:true,
    }

    let Result = '', Text = ''
    let ListStack:string[]    = []
    let ListCounters:number[] = []
    let inPre   = false, inCode     = false
    let inTable = false, inTableRow = false, inTableCell = false
    let TableRows:string[][] = [], currentRow:string[] = [], currentCell = ''
    let lastTag     = ''
    let justStarted = true

  /**** Callbacks for HTML Parser ****/

    const Callbacks:HTMLtoMarkdownCallbacks = {
      processStartTag: function (Tag, Attributes, isUnary, isTopLevel) {
        if (Callbacks.ignoredTag != null) { return }
        if (TagIsToBeIgnored[Tag]) {
          Callbacks.ignoredTag = Tag
          return
        }

        Text = ''
        switch (Tag) {
          case 'h1': case 'h2': case 'h3': case 'h4': case 'h5': case 'h6':
            addNewline(2)
            Text += '#'.repeat(Number(Tag[1])) + ' '
            break
          case 'section': addNewline(2); break
          case 'ul':      addNewline(); ListStack.push('-'); break
          case 'ol':      addNewline(); ListStack.push('1'); ListCounters.push(1); break
          case 'li':
            addNewline()
            Text += ListItemIndentation()
            switch (ListStack[ListStack.length-1]) {
              case '-': Text += '- '; break
              case '1': Text += (ListCounters[ListCounters.length-1]!++) + '. '; break
            }
            break
          case 'table': inTable     = true;    TableRows   = []; break
          case 'tr':    inTableRow  = inTable; currentRow  = []; break
          case 'th':    inTableCell = true;    currentCell = ''; break
          case 'td':    if (inTable && inTableRow && (TableRows.length === 0)) {
                          TableRows.push([])             // add empty header row
                        }
                        inTableCell = true; currentCell = ''
                        break
          case 'blockquote': addNewline();  Text += '> ';                 break
          case 'pre':        addNewline(2); Text += '```'; inPre  = true; break
          case 'code':       if (! inPre) { Text += '`' }  inCode = true; break
          case 'br':                        Text += '  ';  addNewline();  break
          case 'hr':         addNewline(2); Text += '---'; addNewline(2); break
          case 'a':
            Callbacks.href = (Attributes.find(
              (Attribute) => Attribute.Name === 'href'
            ) || {} as any).Value
            Text += '['
            break
          case 'img': {
            let Alt = (Attributes.find((Attribute) => Attribute.Name === 'alt') || {} as any).Value || ''
            let Src = (Attributes.find((Attribute) => Attribute.Name === 'src') || {} as any).Value || ''
            Text += `![${Alt}](${Src})`
            break
          }
          case 'strong': case 'b': Text += '**'; break
          case 'em':     case 'i': Text += '_';  break
        }
        if (inTableCell) { currentCell += Text } else { Result += Text }
        lastTag = Tag
      },

      processEndTag: function (Tag) {
        if (Callbacks.ignoredTag != null) {
          if (Callbacks.ignoredTag === Tag) { delete Callbacks.ignoredTag }
          return
        }

        Text = ''
        switch (Tag) {
          case 'h1': case 'h2': case 'h3': case 'h4': case 'h5': case 'h6':
            Text += ' ' + '#'.repeat(Number(Tag[1]))
            addNewline(2)
            break
          case 'ul': ListStack.pop();                     addNewline(); break
          case 'ol': ListStack.pop(); ListCounters.pop(); addNewline(); break
          case 'li': break                                      // nothing extra
          case 'table':
            if (TableRows.length > 0) {
              addNewline()
                Text += renderMarkdownTable(TableRows); TableRows = []
              addNewline()
            }
            inTable = inTableRow = inTableCell = false
            break
          case 'tr':
            if (inTable) { TableRows.push(currentRow) }
            inTableRow = inTableCell = false; currentRow = []
            break
          case 'th': case 'td':
            if (inTableRow) { currentRow.push(currentCell) }
            inTableCell = false; currentCell = ''
            break
          case 'p':
          case 'blockquote':
            addNewline()
            break
          case 'pre':
            inPre = false
            Text += (Result.endsWith('\n') ? '' : '\n') + '```\n'; addNewline()
            break
          case 'code': if (! inPre) { Text += '`' }; inCode = false; break
          case 'a':
            if (Callbacks.href != null) {
              Text += `](${Callbacks.href})`
              delete Callbacks.href
            }
            break
          case 'strong': case 'b': Text += '**'; break
          case 'em':     case 'i': Text += '_';  break
        }
        if (inTableCell) { currentCell += Text } else { Result += Text }
        lastTag = ''
      },

      processText: function (TextInDocument, isTopLevel) {
        if (Callbacks.ignoredTag != null) { return }

        if ((TextInDocument.trim() === '') && ! inPre && ! inCode) {
          return
        }

        switch (true) {
          case inPre:  Text = TextInDocument;                      break
          case inCode: Text = TextInDocument.replace(/`/g, '\\`'); break
          default:     Text = withDecodedHTMLEntities(TextInDocument).replace(/\s+/g, ' ')
        }
        if (inTableCell) { currentCell += Text } else { Result += Text }

        justStarted = false
      },

      processComment: function (Comment) {
        // ignore comments
      }
    }
    parseHTML(HTMLContent, Callbacks)

    return Result.replace(/^\s+|\s+$/g, '').replace(/\n{3,}/g, '\n\n')

  /**** addNewline ****/

    function addNewline (Count:number = 1):void {
      Text = Text.trimEnd() + '\n'.repeat(Count)
    }

  /**** ListItemIndentation ****/

    function ListItemIndentation ():string {
      return '  '.repeat(ListStack.length - 1)
    }

  /**** withDecodedHTMLEntities ****/

    function withDecodedHTMLEntities (InputText:string):string {
      if (typeof document !== 'undefined') {
        const TextArea = document.createElement('textarea')
        TextArea.innerHTML = InputText
        return TextArea.value
      } else {
        return InputText
          .replace(/&amp;/g,  '&')
          .replace(/&lt;/g,   '<')
          .replace(/&gt;/g,   '>')
          .replace(/&quot;/g, '"')
          .replace(/&apos;/g, '\'')
          .replace(/&#(\d+);/g,     (_, n) => String.fromCodePoint(Number(n)))
          .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCodePoint(parseInt(h, 16)))
      }
    }

  /**** renderMarkdownTable ****/

    function renderMarkdownTable (RowList:string[][]):string {
      if (RowList.length === 0) { return '' }

      let Header:string[], BodyStart:number
        if (RowList[0]!.length > 0) {
          Header    = RowList[0]!                          // real <th> header row
          BodyStart = 1
        } else {                            // no <th> header: synthesize an empty
          const ColumnCount = Math.max(...RowList.map((Row) => Row.length))
          Header    = new Array(ColumnCount).fill('')      // GFM requires a header
          BodyStart = 1                 // skip the empty placeholder row at index 0
        }

      const Alignments = Header.map(() => '---')
      let Lines:string[] = [
        '| ' + Header.join(' | ')     + ' |',
        '| ' + Alignments.join(' | ') + ' |'
      ]
      for (let i = BodyStart; i < RowList.length; i++) {
        Lines.push('| ' + RowList[i]!.join(' | ') + ' |')
      }
      return Lines.join('\n') + '\n'
    }
  }
//----------------------------------------------------------------------------//
//                                HTML Parsing                                //
//----------------------------------------------------------------------------//
// this is my personal variant of the well-known John-Resig-HTML-Parser
// (see https://johnresig.com/blog/pure-javascript-html-parser/)

/**** type definitions ****/

  export type HTMLAttribute = {
    Name:string,
    Value:string,
    escapedValue:string
  }

  export type HTMLAttributeSet = { [Name:string]:HTMLAttribute }

  export type HTMLParserCallbackSet = {
    processStartTag ?: (TagName:string, Attributes:HTMLAttribute[], isUnary:boolean, isTopLevel:boolean) => any,
    processEndTag   ?: (TagName:string, isTopLevel:boolean) => any,
    processText     ?:    (Text:string, isTopLevel:boolean) => any,
    processComment  ?: (Comment:string) => any
  }

  type TagStack = string[] & { last?:() => string|undefined }

/**** parseHTML ****/

  export function parseHTML (HTML:string, Callbacks:HTMLParserCallbackSet):void {
    const StartTagPattern  = /^<([-a-z0-9]+)((?:[\s\xA0]+[-a-z0-9_$:]+(?:[\s\xA0]*=[\s\xA0]*(?:(?:"[^"]*")|(?:'[^']*')|[^>\s\xA0]+))?)*)[\s\xA0]*(\/?)>/i
    const EndTagPattern    = /^<\/([-a-z0-9_]+)[^>]*>/i
    const AttributePattern = /([-a-z0-9_$:]+)(?:[\s\xA0]*=[\s\xA0]*(?:(?:"((?:\\.|[^"])*)")|(?:'((?:\\.|[^'])*)')|([^>\s\xA0]+)))?/gi

  /**** MapOf makes a "map" with keys from a given comma-separated key list ****/

    function MapOf (Elements:string):Record<string,true> {
      let ElementList:string[] = Elements.split(',')
      let Result = Object.create(null) as Record<string,true>
        for (let i = 0, l = ElementList.length; i < l; i++) {
          Result[ElementList[i] as string] = true
        }
      return Result
    }

  /**** maps with the names of tags and attributes with a specific characteristic ****/

    const isEmptyElement = MapOf(
      'area,base,basefont,br,col,embed,frame,hr,img,input,isindex,keygen,link,' +
      'meta,param,source,track,wbr'
    )

    const isBlockElement = MapOf(
      'address,article,aside,audio,blockquote,canvas,center,dd,dir,div,dl,dt,' +
      'fieldset,figcaption,figure,footer,form,frameset,h1,h2,h3,h4,h5,h6,header,' +
      'hgroup,hr,ins,isindex,li,main,menu,nav,noframes,noscript,ol,output,p,pre,' +
      'section,semantics,table,tbody,td,tfoot,th,thead,tr,ul,video,' +
      'svg,g,defs,symbol,clippath,mask,pattern,lineargradient,radialgradient,' +
      'filter,switch,text,tspan,textpath,foreignobject'
    )

    const isInlineElement = MapOf(
      'a,abbr,acronym,applet,b,basefont,bdo,big,br,button,cite,code,del,dfn,em,' +
      'font,i,iframe,img,input,ins,kbd,label,map,object,q,s,samp,script,select,' +
      'small,span,strike,strong,sub,sup,textarea,tt,u,var'
    )

    const isSelfClosingElement = MapOf(
      'area,base,basefont,bgsound,br,col,colgroup,dd,dt,embed,frame,hr,img,' +
      'input,isindex,keygen,li,link,menuitem,meta,options,p,param,source,td,' +
      'tfoot,th,thead,tr,track,wbr,' +
      'rect,circle,ellipse,line,polyline,polygon,path,stop,use,marker,' +
      'animate,animatemotion,animatetransform,set,desc,title,' +
      'feblend,fecolormatrix,fecomponenttransfer,fecomposite,feconvolvematrix,' +
      'fediffuselighting,fedisplacementmap,fedropshadow,feflood,fegaussianblur,' +
      'feimage,femerge,femorphology,feoffset,fespecularlighting,fetile,' +
      'feturbulence,fedistantlight,fepointlight,fespotlight'
    )

    const isSpecialElement = MapOf(
      'script,style'
    )

    const isKeywordAttribute = MapOf(
      'checked,compact,declare,defer,disabled,ismap,multiple,nohref,noresize,' +
      'noshade,nowrap,readonly,selected'
    )

  /**** actual HTML parser ****/

    let doNothing = function () {}

    let processStartTag = Callbacks.processStartTag || doNothing
    let processEndTag   = Callbacks.processEndTag   || doNothing
    let _processText    = Callbacks.processText     || doNothing
    let processComment  = Callbacks.processComment  || doNothing

    let Stack:TagStack = []    // Stack with tag names of unclosed HTML elements
      Stack.last = function last () { return this[this.length-1] }

  /**** text accumulation buffer (fix #6) ****/

    let TextBuffer     = ''
    let TextIsTopLevel = false

    function flushText ():void {
      if (TextBuffer !== '') {
        _processText(TextBuffer, TextIsTopLevel)
        TextBuffer = ''
      }
    }

    function bufferText (Text:string, isTopLevel:boolean):void {
      if (TextBuffer !== '' && isTopLevel !== TextIsTopLevel) { flushText() }
      TextBuffer     += Text
      TextIsTopLevel  = isTopLevel
    }

    function parseStartTag (_:string, TagName:string, Rest:string, isUnary:string):string {
      TagName = TagName.toLowerCase()

      if (isBlockElement[TagName]) {            // close pending inline elements
        while ((Stack.last!() != null) && isInlineElement[Stack.last!()!]) {
          parseEndTag('', Stack.last!()!)
        }
      }

      if (isSelfClosingElement[TagName] && (Stack.last!() === TagName)) {
        parseEndTag('', TagName)
      }

      let _isUnary = isEmptyElement[TagName] || ! !isUnary
      if (! _isUnary) { Stack.push(TagName) }

      if (processStartTag !== doNothing) {
        let Attributes:HTMLAttribute[] = []
          Rest.replace(AttributePattern, function(Match:string, AttributeName:string, ...args:any[]):string {
            let AttributeValue = (args[0] ? args[0] :
              (args[1] ? args[1] :
                (args[2] ? args[2] :
                  (isKeywordAttribute[AttributeName] ? AttributeName : ''))))
            Attributes.push({
              Name:AttributeName, Value:AttributeValue,
              escapedValue:escapedHTMLAttribute(AttributeValue)
            })
            return ''
          })
        flushText()
        processStartTag(
          TagName, Attributes, _isUnary, (Stack.length === (_isUnary ? 0 : 1))
        )
      }

      return ''
    }

    function parseEndTag (_?:string, TagName?:string):string {
      let Position:number           // how many open elements have to be closed?
      if (TagName == null) {
        Position = 0
      } else {
        TagName = TagName.toLowerCase()

        for (Position = Stack.length-1; Position >= 0; Position--) {
          if (Stack[Position] === TagName) { break }
        }
      }

      if (Position >= 0) {
        flushText()
        for (let i = Stack.length-1; i >= Position; i--) {
          processEndTag(Stack[i]!, (i === 0))
        }
        Stack.length = Position
      }

      return ''
    }

    let lastHTMLContent = HTML
    while (HTML !== '') {
      let inText = true

      if ((Stack.last!() == null) || ! isSpecialElement[Stack.last!()!]) {
        if (HTML.startsWith('<!--')) {                            // HTML comment
          let Index = HTML.indexOf('-->',4)
          if (Index > 0) {
            flushText()
            processComment(HTML.slice(4,Index))
            HTML   = HTML.slice(Index + 3)
            inText = false
          }
        } else if (HTML.startsWith('<?')) {      // skip processing instructions
          let Index = HTML.indexOf('?>')
          if (Index >= 0) {
            HTML   = HTML.slice(Index + 2)
            inText = false
          }
        } else if (HTML.startsWith('<!')) {               // skip DOCTYPE et al.
          let Index = HTML.indexOf('>')
          if (Index >= 0) {
            HTML   = HTML.slice(Index + 1)
            inText = false
          }
        } else if (HTML.startsWith('</')) {                      // HTML end tag
          let Match = HTML.match(EndTagPattern)
          if (Match != null) {
            HTML = HTML.slice(Match[0].length)
            Match[0].replace(EndTagPattern, parseEndTag)     // for side effects
            inText = false
          }
        } else if (HTML.startsWith('<')) {                     // HTML start tag
          let Match = HTML.match(StartTagPattern)
          if (Match != null) {
            HTML = HTML.slice(Match[0].length)
            Match[0].replace(StartTagPattern, parseStartTag) // for side effects
            inText = false
          }
        }

        if (inText) {
          let Index = HTML.indexOf('<')

          let Text = (Index < 0 ? HTML : HTML.slice(0,Index))
          HTML     = (Index < 0 ? ''   : HTML.slice(Index))

          bufferText(Text, Stack.length === 0)
        }
      } else {
        HTML = HTML.replace(
          new RegExp('^((?:.|\n)*?)<\\/' + Stack.last!() + '[^>]*>','i'),
          function (_:string, Text:string):string {
            Text = Text
              .replace(/<!--(.*?)-->/g, '$1')
              .replace(/<!\[CDATA\[(.*?)]]>/g, '$1')
            bufferText(Text, Stack.length === 0)
            return ''
          }
        )
        parseEndTag('', Stack.last!())
      }

      if (HTML === lastHTMLContent) {
        switch (true) {
          case HTML.startsWith('<'):
            HTML = HTML.slice(1)
            bufferText('<', Stack.length === 0)
            break
          default:
            throw new Error('HTMLParseError: could not parse "' + HTML + '"')
        }
      }
      lastHTMLContent = HTML
    }
    flushText()
    parseEndTag()
  }

/**** AttributeFrom ****/

  export function AttributeFrom (
    AttributeName:string, Attributes:HTMLAttribute[]
  ):string|undefined {
    for (let i = 0, l = Attributes.length; i < l; i++) {
      let Attribute = Attributes[i]
      if (Attribute!.Name === AttributeName) { return Attribute!.Value }
    }
    return undefined
  }

/**** serializedTag ****/

  export function serializedTag (
    TagName:string, Attributes:HTMLAttribute[], isUnary:boolean
  ):string {
    let Result = '<' + TagName
      for (let i = 0, l = Attributes.length; i < l; i++) {
        let Attribute = Attributes[i]
        Result += ' ' + Attribute!.Name + '="' + Attribute!.escapedValue + '"'
      }
    return Result + (isUnary ? '/>' : '>')
  }

/**** escapedHTMLAttribute ****/

  export function escapedHTMLAttribute (OriginalValue:string):string {
    return OriginalValue.replace(
      /[&<>"'\x00-\x1F\x7F-\x9F\\]/g, function (Match:string):string {
        switch (Match) {
          case '&':  return '&amp;'
          case '<':  return '&lt;'
          case '>':  return '&gt;'
          case '"':  return '&quot;'
          case "'":  return '&apos;'
          case '\n': return '\n'            // allows line feeds to be preserved
          case '\\': return '&#92;'
          default:   let Result = Match.charCodeAt(0).toString(16)
                     return '&#x0000'.substring(0,7-Result.length) + Result + ';'
        }
      }
    )
  }

/**** unescapedHTMLAttribute ****/

  export function unescapedHTMLAttribute (OriginalValue:string):string {
    return OriginalValue.replace(
      /&(amp|lt|gt|quot|apos|#92|#x[0-9a-fA-F]{1,6}|#[0-9]{1,7});/g, function (Match:string):string {
        switch (Match) {
          case '&amp;':  return '&'
          case '&lt;':   return '<'
          case '&gt;':   return '>'
          case '&quot;': return '"'
          case '&apos;': return '\''
          case '&#92;':  return '\\'
          default:
            const isHex = (Match.charAt(2) === 'x') || (Match.charAt(2) === 'X')
            const Code  = isHex
              ? parseInt(Match.slice(3,-1),16) // "&#x....;" (skip "&#x" and ";")
              : parseInt(Match.slice(2,-1),10) // "&#....;"  (skip "&#"  and ";")
            return String.fromCodePoint(Code)
        }
      }
    )
  }


