/**** executeCallback ****/

  export function executeCallback (
    Description:JCL_Textline, Callback:Function|undefined, ...ArgList:any[]
  ):any {
    expectTextline('callback description',Description)
    allowFunction             ('callback',Callback)

    if (Callback != null) {
      try {
        return Callback(...ArgList)
      } catch (Signal:any) {
        throwError(`CallbackFailure: ${Description} failed with ${''+Signal}`)
      }
    }
  }
  export const executedCallback = executeCallback

/**** capitalized ****/

  export function capitalized (Textline:JCL_Textline):JCL_Textline {
    expectTextline('Textline',Textline)
    if (Textline.length === 0) {
      return Textline
    } else {
      return Textline.charAt(0).toUpperCase() + Textline.slice(1)
    }
  }
